		internal unsafe static void Free<T>(Allocator allocator, ref T* ptr) where T : unmanaged
		{
			if (ptr == null)
			{
				return;
			}
			T* ptr2 = ptr;
			ptr = null;
			try
			{
				allocator.FreeInternal(ptr2);
			}
			catch (Exception error)
			{
				InternalLogStreams.LogException?.Log(error);
			}
		}

