		{
			string text = string.Join(", ", from region in regionHandler.EnabledRegions.AsEnumerable()
				select region.Code + "[" + region.HostAndPort + "]");
			InternalLogStreams.LogDebug?.Log("OnRegionListReceived: EnabledRegions=" + text);
		}

