	internal static class ScheduledRequestsExt
	{
		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public static bool IsSet(this ref ScheduledRequests requests, ScheduledRequests target)
		{
			return (requests & target) == target;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public static void Set(this ref ScheduledRequests requests, ScheduledRequests target)
		{
			requests |= target;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public static void Clear(this ref ScheduledRequests requests, ScheduledRequests target)
		{
			requests &= ~target;
		}
	}
	internal static class DisconnectCauseExt
	{
		public static ShutdownReason ConvertToShutdownReason(DisconnectCause disconnectCause)
		{
			switch (disconnectCause)
			{
			case DisconnectCause.None:
			case DisconnectCause.DisconnectByClientLogic:
				return ShutdownReason.Ok;
			case DisconnectCause.ExceptionOnConnect:
			case DisconnectCause.DnsExceptionOnConnect:
			case DisconnectCause.ServerAddressInvalid:
			case DisconnectCause.Exception:
			case DisconnectCause.OperationNotAllowedInCurrentState:
			case DisconnectCause.DisconnectByOperationLimit:
				return ShutdownReason.Error;
			case DisconnectCause.ServerTimeout:
			case DisconnectCause.ClientTimeout:
				return ShutdownReason.PhotonCloudTimeout;
			case DisconnectCause.DisconnectByServerLogic:
			case DisconnectCause.DisconnectByServerReasonUnknown:
			case DisconnectCause.DisconnectByDisconnectMessage:
				return ShutdownReason.DisconnectedByPluginLogic;
			case DisconnectCause.InvalidAuthentication:
				return ShutdownReason.InvalidAuthentication;
			case DisconnectCause.CustomAuthenticationFailed:
				return ShutdownReason.CustomAuthenticationFailed;
			case DisconnectCause.AuthenticationTicketExpired:
				return ShutdownReason.AuthenticationTicketExpired;
			case DisconnectCause.MaxCcuReached:
				return ShutdownReason.MaxCcuReached;
			case DisconnectCause.InvalidRegion:
				return ShutdownReason.InvalidRegion;
			default:
				return ShutdownReason.Ok;
			}
		}
	}
	internal static class DisconnectReasonExt
	{
		public static ShutdownReason ConvertToShutdownReason(DisconnectReason disconnectCause)
		{
			return disconnectCause switch
			{
				DisconnectReason.IncompatibleConfiguration => ShutdownReason.IncompatibleConfiguration, 
				DisconnectReason.ServerAlreadyInRoom => ShutdownReason.ServerInRoom, 
				DisconnectReason.ServerLogic => ShutdownReason.DisconnectedByPluginLogic, 
				_ => ShutdownReason.Error, 
			};
		}
	}
	internal static class ErrorCodeExt
	{
		public static ShutdownReason ConvertToShutdownReason(short errorCode)
		{
			switch (errorCode)
			{
			case 0:
				return ShutdownReason.Ok;
			case 32751:
				InternalLogStreams.LogDebug?.Error("Fusion plug-in not found. Make sure to use a Fusion-type Photon Application ID.");
				return ShutdownReason.IncompatibleConfiguration;
			case 32766:
				return ShutdownReason.GameIdAlreadyExists;
			case 32758:
			case 32760:
				return ShutdownReason.GameNotFound;
			case 32765:
				return ShutdownReason.GameIsFull;
			case 32764:
				return ShutdownReason.GameClosed;
			case 32757:
				return ShutdownReason.MaxCcuReached;
			case 32756:
				return ShutdownReason.InvalidRegion;
			case short.MaxValue:
				return ShutdownReason.InvalidAuthentication;
			case 32753:
				return ShutdownReason.AuthenticationTicketExpired;
			case 32755:
				return ShutdownReason.CustomAuthenticationFailed;
			case 32752:
				return ShutdownReason.Error;
			case 32762:
				InternalLogStreams.LogDebug?.Error("All servers are busy. This is a temporary issue and the game logic should try again after a brief wait time.");
				return ShutdownReason.Error;
			default:
				return ShutdownReason.Error;
			}
		}
	}
