		{
			[MethodImpl(MethodImplOptions.AggressiveInlining)]
			get
			{
				return _runner;
			}
		}

		public NetworkObject Object
		{
			[MethodImpl(MethodImplOptions.AggressiveInlining)]
			get
			{
				return _object;
			}
		}

		public virtual void FixedUpdateNetwork()
