		{
			NetworkBehaviourUtils.InternalOnDisable(this);
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		internal void MakeOwned(NetworkRunner runner, NetworkObject obj)
		{
			_runner = runner;
			_object = obj;
