		private const int WORD_COUNT = 1;

		public const int MAX_HITBOXES = 31;

		[InlineHelp]
		public ConfigFlags Config = ConfigFlags.Default;

		[InlineHelp]
		[Unit(Units.Units)]
		public float BroadRadius;

		[InlineHelp]
		public Vector3 Offset;

		[InlineHelp]
		public Color GizmosColor = Color.gray;

		[InlineHelp]
		[Space(4f)]
		public Hitbox[] Hitboxes;

		internal Transform CachedTransform;

		public bool HitboxRootActive
		{
			[MethodImpl(MethodImplOptions.AggressiveInlining)]
			get
			{
				return (ReinterpretState<uint>() & 1) == 0;
			}
			set
			{
				if (value)
				{
					ReinterpretState<uint>() &= 4294967294u;
				}
				else
				{
					ReinterpretState<uint>() |= 1u;
				}
			}
		}

		internal bool Registered => BehaviourUtils.IsAlive(Manager);

		public HitboxManager Manager { get; internal set; }

		public bool InInterest => base.Runner.IsInterestedIn(base.Object, base.Runner.LocalPlayer) ?? true;

		private void Awake()
		{
			CachedTransform = base.transform;
		}

		public void OnDrawGizmos()
		{
			base.transform.GetPositionAndRotation(out var position, out var rotation);
			Matrix4x4 localToWorldMatrix = Matrix4x4.TRS(position, rotation, Vector3.one);
			DrawGizmos(GizmosColor, ref localToWorldMatrix);
		}

		protected virtual void DrawGizmos(Color color, ref Matrix4x4 localToWorldMatrix)
		{
			Gizmos.matrix = localToWorldMatrix;
			Gizmos.color = color;
			Gizmos.DrawWireSphere(Offset, BroadRadius);
			Gizmos.color = Color.white;
			Gizmos.matrix = Matrix4x4.identity;
		}

		[EditorButton("Find Hitboxes", EditorButtonVisibility.EditMode, 0, false)]
		public void InitHitboxes()
		{
			bool includeInactive = (Config & ConfigFlags.IncludeInactiveHitboxes) == ConfigFlags.IncludeInactiveHitboxes;
			Hitboxes = base.transform.GetNestedComponentsInChildren<Hitbox, NetworkObject>(null, includeInactive).ToArray();
			if (Hitboxes.Length > 31)
			{
				UnityEngine.Debug.LogWarning($"Hitbox count above limit per root, clamped to max {31}");
				Array.Resize(ref Hitboxes, 31);
			}
			for (int i = 0; i < Hitboxes.Length; i++)
			{
				Hitbox hitbox = Hitboxes[i];
				hitbox._hitboxIndex = i;
				hitbox.Root = this;
			}
			if (BroadRadius == 0f)
			{
				SetMinBoundingRadius();
			}
		}

		[EditorButton("Quick Set BroadRadius", EditorButtonVisibility.Always, 0, true)]
		public void SetMinBoundingRadius()
		{
			if (Hitboxes.Length == 0)
			{
				return;
			}
			Vector3 vector = base.transform.position + base.transform.rotation * Offset;
			float num = 0f;
			Hitbox[] hitboxes = Hitboxes;
			foreach (Hitbox hitbox in hitboxes)
			{
				if (hitbox.Type != HitboxTypes.None)
				{
					Vector3 vector2 = hitbox.transform.position + hitbox.transform.rotation * hitbox.Offset;
					float num2 = (vector2 - vector).magnitude;
					switch (hitbox.Type)
					{
					case HitboxTypes.Sphere:
						num2 += hitbox.AbsSphereRadius;
						break;
					case HitboxTypes.Box:
						num2 += hitbox.BoxExtents.magnitude;
						break;
					case HitboxTypes.Capsule:
						num2 += Mathf.Max(hitbox.CapsuleExtents * 0.5f, hitbox.CapsuleRadius);
						break;
					}
					if (num2 > num)
					{
						num = num2;
					}
				}
			}
			BroadRadius = num;
		}

		public void SetHitboxActive(Hitbox hitbox, bool setActive)
		{
			if ((uint)hitbox.HitboxIndex >= 31u)
			{
				throw new ArgumentOutOfRangeException($"Hitbox index {hitbox.HitboxIndex} is outside the valid range: [0, {31})");
			}
			if (!BehaviourUtils.IsSame(this, hitbox.Root))
			{
				Assert.Fail(string.Format("Hitbox '{0}' is part of a different HitboxRoot '{1}' than this '{2}'. Are you missing a call to {3} to update the root reference?", hitbox, hitbox.Root, this, "InitHitboxes"));
			}
			else if (hitbox.HitboxIndex >= Hitboxes.Length || !BehaviourUtils.IsSame(Hitboxes[hitbox.HitboxIndex], hitbox))
			{
				Assert.Fail(string.Format("Hitbox '{0}' (index {1}) does not match Root's Hitbox of same index: '{2}'. Are you missing a call to {3} to update the root reference?", hitbox, hitbox.HitboxIndex, Hitboxes[hitbox.HitboxIndex], "InitHitboxes"));
			}
			else
			{
				SetHitboxActiveFastUnchecked(hitbox, setActive);
			}
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		internal void SetHitboxActiveFastUnchecked(Hitbox hitbox, bool setActive)
		{
			if (setActive)
			{
				ReinterpretState<uint>() &= ~hitbox.HitboxMask;
			}
			else
			{
				ReinterpretState<uint>() |= hitbox.HitboxMask;
			}
		}

		public bool IsHitboxActive(Hitbox hitbox)
		{
			if ((uint)hitbox.HitboxIndex >= 31u)
			{
				throw new ArgumentOutOfRangeException($"Hitbox index {hitbox.HitboxIndex} is outside the valid range: [0, {31})");
			}
			if (!BehaviourUtils.IsSame(this, hitbox.Root))
			{
				Assert.Fail(string.Format("Hitbox '{0}' is part of a different HitboxRoot '{1}' than this '{2}'. Are you missing a call to {3} to update the root reference?", hitbox, hitbox.Root, this, "InitHitboxes"));
				return false;
			}
			if (hitbox.HitboxIndex >= Hitboxes.Length || !BehaviourUtils.IsSame(Hitboxes[hitbox.HitboxIndex], hitbox))
			{
				Assert.Fail(string.Format("Hitbox '{0}' (index {1}) does not match Root's Hitbox of same index: '{2}'. Are you missing a call to {3} to update the root reference?", hitbox, hitbox.HitboxIndex, Hitboxes[hitbox.HitboxIndex], "InitHitboxes"));
				return false;
			}
			return IsHitboxActiveFastUnchecked(hitbox);
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		internal bool IsHitboxActiveFastUnchecked(Hitbox hitbox)
		{
			return (ReinterpretState<uint>() & hitbox.HitboxMask) == 0;
		}

		public override void Despawned(NetworkRunner runner, bool hasState)
		{
			if (Registered && BehaviourUtils.IsAlive(Manager))
			{
				HitboxManager manager = Manager;
				Manager = null;
				manager.Remove(this);
			}
		}

		internal void RegisterColliders(IHitboxColliderContainer container, int tick)
		{
			if ((Config & ConfigFlags.ReinitializeHitboxesBeforeRegistration) == ConfigFlags.ReinitializeHitboxesBeforeRegistration)
			{
				InitHitboxes();
			}
			if (Hitboxes == null)
			{
				return;
			}
			Hitbox[] hitboxes = Hitboxes;
			foreach (Hitbox hitbox in hitboxes)
			{
				int index;
				ref HitboxCollider nextCollider = ref container.GetNextCollider(out index);
				if (!hitbox.gameObject.activeSelf)
				{
					hitbox.CacheInfo();
				}
				hitbox.SetColliderData(ref nextCollider, tick);
				hitbox.ColliderIndex = index;
			}
		}

		internal void DeregisterColliders(IHitboxColliderContainer container)
		{
			if (Hitboxes == null)
			{
				return;
			}
			Hitbox[] hitboxes = Hitboxes;
			foreach (Hitbox hitbox in hitboxes)
			{
				if (hitbox.ColliderIndex > 0)
				{
					container.ReleaseCollider(hitbox.ColliderIndex);
				}
			}
		}

		internal Bounds GetBounds()
		{
			Vector3 vector = base.transform.TransformPoint(Offset);
			return new Bounds
			{
				min = new Vector3(vector.x - BroadRadius, vector.y - BroadRadius, vector.z - BroadRadius),
				max = new Vector3(vector.x + BroadRadius, vector.y + BroadRadius, vector.z + BroadRadius)
			};
		}
	}
	[StructLayout(LayoutKind.Explicit)]
	[NetworkStructWeaved(1)]
	public struct Angle : INetworkStruct, IEquatable<Angle>
	{
		public const int SIZE = 4;

		private const int ACCURACY = 10000;

		private const int DECIMALS = 4;

		private const int _360 = 3600000;

		[FieldOffset(0)]
		private int _value;

		public void Clamp(Angle min, Angle max)
		{
			Assert.Check(max._value >= min._value);
			if (_value < min._value)
			{
				_value = min._value;
			}
			if (_value > max._value)
			{
				_value = max._value;
			}
		}

		public static Angle Min(Angle a, Angle b)
		{
			return (a._value < b._value) ? a : b;
		}

		public static Angle Max(Angle a, Angle b)
		{
			return (a._value > b._value) ? a : b;
		}

		public static Angle Lerp(Angle a, Angle b, float t)
		{
			if (a._value == b._value)
			{
				return a;
			}
			return Mathf.LerpAngle((float)a, (float)b, t);
		}

		public static Angle Clamp(Angle value, Angle min, Angle max)
		{
			if (max._value < min._value)
			{
				Angle angle = max;
				max = min;
				min = angle;
			}
			if (value._value < min._value)
			{
				return min;
			}
			if (value._value > max._value)
			{
				return max;
			}
			return value;
		}

		public static bool operator <(Angle a, Angle b)
		{
			return a._value < b._value;
		}

		public static bool operator <=(Angle a, Angle b)
		{
			return a._value <= b._value;
		}

		public static bool operator >(Angle a, Angle b)
		{
			return a._value > b._value;
		}

		public static bool operator >=(Angle a, Angle b)
		{
			return a._value >= b._value;
		}

		public static bool operator ==(Angle a, Angle b)
		{
			return a._value == b._value;
		}

		public static bool operator !=(Angle a, Angle b)
		{
			return a._value != b._value;
		}

		public bool Equals(Angle other)
		{
			return _value == other._value;
		}

		public override bool Equals(object obj)
		{
			return obj is Angle other && Equals(other);
		}

		public override int GetHashCode()
		{
			return _value;
		}

		public static Angle operator +(Angle a, Angle b)
		{
			Assert.Check(a._value >= 0 && a._value <= 3600000);
			Assert.Check(b._value >= 0 && b._value <= 3600000);
			a._value += b._value;
			if (a._value > 3600000)
			{
				a._value %= 3600000;
			}
			return a;
		}

		public static Angle operator -(Angle a, Angle b)
		{
			Assert.Check(a._value >= 0 && a._value <= 3600000);
			Assert.Check(b._value >= 0 && b._value <= 3600000);
			a._value -= b._value;
			if (a._value < 0)
			{
				Assert.Check(a._value >= -3600000);
				a._value = 3600000 + a._value;
			}
			return a;
		}

		public static explicit operator float(Angle value)
		{
			return (float)((double)value._value / 10000.0);
		}

		public static explicit operator double(Angle value)
		{
			return (double)value._value / 10000.0;
		}

		public static implicit operator Angle(double value)
		{
			if (value > 360.0)
			{
				value %= 360.0;
			}
			else if (value < 0.0)
			{
				value = ((!(value < -360.0)) ? (360.0 + value) : (360.0 + value % -360.0));
			}
			Angle result = default(Angle);
			result._value = (int)(value * 10000.0 + 0.5);
			return result;
		}

		public static implicit operator Angle(float value)
		{
			return (double)value;
		}

		public static implicit operator Angle(int value)
		{
			if (value > 360)
			{
				value %= 360;
			}
			else if (value < 0)
			{
				value = ((value >= -360) ? (360 + value) : (360 + value % -360));
			}
			Angle result = default(Angle);
			result._value = value * 10000;
			return result;
		}

		public override string ToString()
		{
			string text = (_value % 10000).ToString();
			if (text.Length < 4)
			{
				text = new string('0', 4 - text.Length) + text;
			}
			return $"[Angle:{_value / 10000}.{text}]";
		}
	}
	internal static class ArraySpecialized
	{
		private const int IntrosortSizeThreshold = 16;

		private static int FloorLog2(int n)
		{
			int num = 0;
			while (n >= 1)
			{
				num++;
				n /= 2;
			}
			return num;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		private static void Swap<T>(T[] a, int i, int j)
		{
			Assert.Check(i != j);
			T val = a[i];
			a[i] = a[j];
			a[j] = val;
		}

		public static void Sort(int[] array, int index, int length)
		{
			if (length >= 2)
			{
				IntroSort(array, index, length + index - 1, 2 * FloorLog2(array.Length));
			}
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		private static int Compare(int x, int y)
		{
			return x - y;
		}

		private static void SwapIfGreater(int[] array, int a, int b)
		{
			if (a != b && Compare(array[a], array[b]) > 0)
			{
				int num = array[a];
				array[a] = array[b];
				array[b] = num;
			}
		}

		private static void IntroSort(int[] array, int lo, int hi, int depthLimit)
		{
			while (hi > lo)
			{
				int num = hi - lo + 1;
				if (num <= 16)
				{
					switch (num)
					{
					case 1:
						break;
					case 2:
						SwapIfGreater(array, lo, hi);
						break;
					case 3:
						SwapIfGreater(array, lo, hi - 1);
						SwapIfGreater(array, lo, hi);
						SwapIfGreater(array, hi - 1, hi);
						break;
					default:
						InsertionSort(array, lo, hi);
						break;
					}
					break;
				}
				if (depthLimit == 0)
				{
					Heapsort(array, lo, hi);
					break;
				}
				depthLimit--;
				int num2 = PickPivotAndPartition(array, lo, hi);
				IntroSort(array, num2 + 1, hi, depthLimit);
				hi = num2 - 1;
			}
		}

		private static int PickPivotAndPartition(int[] array, int lo, int hi)
		{
			int num = lo + (hi - lo) / 2;
			SwapIfGreater(array, lo, num);
			SwapIfGreater(array, lo, hi);
			SwapIfGreater(array, num, hi);
			int num2 = array[num];
			Swap(array, num, hi - 1);
			int num3 = lo;
			int num4 = hi - 1;
			while (num3 < num4)
			{
				while (Compare(array[++num3], num2) < 0)
				{
				}
				while (Compare(num2, array[--num4]) < 0)
				{
				}
				if (num3 >= num4)
				{
					break;
				}
				Swap(array, num3, num4);
			}
			if (num3 != hi - 1)
			{
				Swap(array, num3, hi - 1);
			}
			return num3;
		}

		private static void Heapsort(int[] array, int lo, int hi)
		{
			int num = hi - lo + 1;
			for (int num2 = num / 2; num2 >= 1; num2--)
			{
				DownHeap(array, num2, num, lo);
			}
			for (int num3 = num; num3 > 1; num3--)
			{
				Swap(array, lo, lo + num3 - 1);
				DownHeap(array, 1, num3 - 1, lo);
			}
		}

		private static void DownHeap(int[] array, int i, int n, int lo)
		{
			int num = array[lo + i - 1];
			while (i <= n / 2)
			{
				int num2 = 2 * i;
				if (num2 < n && Compare(array[lo + num2 - 1], array[lo + num2]) < 0)
				{
					num2++;
				}
				if (Compare(num, array[lo + num2 - 1]) >= 0)
				{
					break;
				}
				array[lo + i - 1] = array[lo + num2 - 1];
				i = num2;
			}
			array[lo + i - 1] = num;
		}

		private static void InsertionSort(int[] array, int lo, int hi)
		{
			for (int i = lo; i < hi; i++)
			{
				int num = i;
				int num2 = array[i + 1];
				while (num >= lo && Compare(num2, array[num]) < 0)
				{
					array[num + 1] = array[num];
					num--;
				}
				array[num + 1] = num2;
			}
		}

		public static void Sort(SimulationInput[] array, int index, int length)
		{
			if (length >= 2)
			{
				IntroSort(array, index, length + index - 1, 2 * FloorLog2(array.Length));
			}
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		private unsafe static int Compare(SimulationInput x, SimulationInput y)
		{
			return x.Header->Tick.CompareTo(y.Header->Tick);
		}

		private static void SwapIfGreater(SimulationInput[] array, int a, int b)
		{
			if (a != b && Compare(array[a], array[b]) > 0)
			{
				SimulationInput simulationInput = array[a];
				array[a] = array[b];
				array[b] = simulationInput;
			}
		}

		private static void IntroSort(SimulationInput[] array, int lo, int hi, int depthLimit)
		{
			while (hi > lo)
			{
				int num = hi - lo + 1;
				if (num <= 16)
				{
					switch (num)
					{
					case 1:
						break;
					case 2:
						SwapIfGreater(array, lo, hi);
						break;
					case 3:
						SwapIfGreater(array, lo, hi - 1);
						SwapIfGreater(array, lo, hi);
						SwapIfGreater(array, hi - 1, hi);
						break;
					default:
						InsertionSort(array, lo, hi);
						break;
					}
					break;
				}
				if (depthLimit == 0)
				{
					Heapsort(array, lo, hi);
					break;
				}
				depthLimit--;
				int num2 = PickPivotAndPartition(array, lo, hi);
				IntroSort(array, num2 + 1, hi, depthLimit);
				hi = num2 - 1;
			}
		}

		private static int PickPivotAndPartition(SimulationInput[] array, int lo, int hi)
		{
			int num = lo + (hi - lo) / 2;
			SwapIfGreater(array, lo, num);
			SwapIfGreater(array, lo, hi);
			SwapIfGreater(array, num, hi);
			SimulationInput simulationInput = array[num];
			Swap(array, num, hi - 1);
			int num2 = lo;
			int num3 = hi - 1;
			while (num2 < num3)
			{
				while (Compare(array[++num2], simulationInput) < 0)
				{
				}
				while (Compare(simulationInput, array[--num3]) < 0)
				{
				}
				if (num2 >= num3)
				{
					break;
				}
				Swap(array, num2, num3);
			}
			if (num2 != hi - 1)
			{
				Swap(array, num2, hi - 1);
			}
			return num2;
		}

		private static void Heapsort(SimulationInput[] array, int lo, int hi)
		{
			int num = hi - lo + 1;
			for (int num2 = num / 2; num2 >= 1; num2--)
			{
				DownHeap(array, num2, num, lo);
			}
			for (int num3 = num; num3 > 1; num3--)
			{
				Swap(array, lo, lo + num3 - 1);
				DownHeap(array, 1, num3 - 1, lo);
			}
		}

		private static void DownHeap(SimulationInput[] array, int i, int n, int lo)
		{
			SimulationInput simulationInput = array[lo + i - 1];
			while (i <= n / 2)
			{
				int num = 2 * i;
				if (num < n && Compare(array[lo + num - 1], array[lo + num]) < 0)
				{
					num++;
				}
				if (Compare(simulationInput, array[lo + num - 1]) >= 0)
				{
					break;
				}
				array[lo + i - 1] = array[lo + num - 1];
				i = num;
			}
			array[lo + i - 1] = simulationInput;
		}

		private static void InsertionSort(SimulationInput[] array, int lo, int hi)
		{
			for (int i = lo; i < hi; i++)
			{
				int num = i;
				SimulationInput simulationInput = array[i + 1];
				while (num >= lo && Compare(simulationInput, array[num]) < 0)
				{
					array[num + 1] = array[num];
					num--;
				}
				array[num + 1] = simulationInput;
			}
		}
	}
