		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public static bool IsNotNull(Behaviour obj)
		{
			return (object)obj != null;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public static bool IsAlive(NetworkRunner obj)
		{
