	public struct FixedArray<T> : IEnumerable<T>, IEnumerable where T : unmanaged
	{
		public struct Enumerator : IEnumerator<T>, IEnumerator, IDisposable
		{
			private int _index;

			private FixedArray<T> _array;

			public T Current
			{
