			if (equalityComparer == null)
			{
				equalityComparer = EqualityComparer<V>.Default;
			}
			while (enumerator.MoveNext())
			{
				if (equalityComparer.Equals(enumerator.Current.Value, value))
				{
					return true;
				}
			}
			enumerator.Dispose();
			return false;
		}

