	public static class ReadWriteUtilsForWeaver
	{
		private const float ACCURACY = 1024f;

		private const int STRING_LENGTH_INDEX = 0;

		private const int STRING_HASHCODE_INDEX = 1;

		private const int STRING_DATA_INDEX = 2;

		private const int STRING_NOHASHCODE_DATA_INDEX = 1;

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		[Preserve]
		public unsafe static bool ReadBoolean(int* data)
		{
			return (*data != 0) ? true : false;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		[Preserve]
		public unsafe static void WriteBoolean(int* data, bool value)
		{
			*data = (value ? 1 : 0);
		}

		[Preserve]
		public unsafe static int GetByteArrayHashCode(byte* ptr, int length)
		{
			return HashCodeUtilities.GetArrayHashCode(ptr, length);
		}

		[Preserve]
		public unsafe static int WriteStringUtf8NoHash(void* destination, string str)
		{
			return Native.WriteLengthPrefixedUTF8(destination, str);
		}

		[Preserve]
		public unsafe static int ReadStringUtf8NoHash(void* source, out string result)
		{
			return Native.ReadLengthPrefixedUTF8(source, out result);
		}

		[Preserve]
		public static int GetByteCountUtf8NoHash(string value)
		{
			return Native.GetLengthPrefixedUTF8ByteCount(value);
		}

		[Preserve]
		public static int GetStringHashCode(string value, int maxLength)
		{
			int len = Math.Min(value.Length, maxLength);
			return value.GetHashDeterministicInternal(len, 352654597);
		}

		[Preserve]
		public unsafe static int WriteStringUtf32NoHash(int* ptr, int maxLength, string value)
		{
			if (string.IsNullOrEmpty(value))
			{
				*ptr = 0;
				return 4;
			}
			UTF32Tools.ConversionResult conversionResult = UTF32Tools.Convert(value, (uint*)(ptr + 1), maxLength);
			*ptr = conversionResult.CodePointCount;
			return (conversionResult.CodePointCount + 1) * 4;
		}

		[Preserve]
		public unsafe static int ReadStringUtf32NoHash(int* ptr, int maxLength, out string result)
		{
			int num = Math.Min(*ptr, maxLength);
			int* value = ptr + 1;
			if (num == 0)
			{
				result = "";
			}
			else
			{
				result = new string((sbyte*)value, 0, num * 4, Encoding.UTF32);
			}
			return (num + 1) * 4;
		}

		[Preserve]
		public unsafe static int WriteStringUtf32WithHash(int* ptr, int maxLength, string value, ref string cache)
		{
			if (string.IsNullOrEmpty(value))
			{
				*ptr = 0;
				ptr[1] = 0;
				return 8;
			}
			UTF32Tools.ConversionResult conversionResult = UTF32Tools.Convert(value, (uint*)(ptr + 2), maxLength);
			*ptr = conversionResult.CodePointCount;
			Assert.Check(conversionResult.CharacterCount <= value.Length);
			if (conversionResult.CharacterCount < value.Length)
			{
				cache = value.Substring(0, conversionResult.CharacterCount);
			}
			else
			{
				cache = value;
			}
			ptr[1] = cache.GetHashDeterministic();
			return (conversionResult.CodePointCount + 2) * 4;
		}

		[Preserve]
		public unsafe static int ReadStringUtf32WithHash(int* ptr, int maxLength, ref string cache)
		{
			int num = Math.Min(*ptr, maxLength);
			int num2 = ptr[1];
			int* ptr2 = ptr + 2;
			if (num == 0)
			{
				cache = "";
			}
			else
			{
				if (cache != null && num >= cache.Length / 2 && num <= cache.Length && num2 == cache.GetHashCode() && UTF32Tools.CompareOrdinal(cache, (uint*)ptr2, num) == 0)
				{
					return (2 + num) * 4;
				}
				cache = new string((sbyte*)ptr2, 0, num * 4, Encoding.UTF32);
			}
			return (2 + num) * 4;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		[Preserve]
		public static int GetWordCountString(int capacity, bool withCaching)
		{
			if (withCaching)
			{
				return 2 + capacity;
			}
			return 1 + capacity;
		}

		[Preserve]
		public static int VerifyRawNetworkUnwrap<T>(int actual, int maxBytes)
		{
			if (actual > maxBytes)
			{
				throw new InvalidOperationException($"Overflow when unwrapping {typeof(T).FullName}: expected max {maxBytes}, got {actual}");
			}
			return actual;
		}

		[Preserve]
		public static int VerifyRawNetworkWrap<T>(int actual, int maxBytes)
		{
			if (actual > maxBytes)
			{
				throw new InvalidOperationException($"Overflow when wrapping {typeof(T).FullName}: expected max {maxBytes}, got {actual}");
			}
			return actual;
		}
	}
	public static class ReflectionUtils
	{
		public static T GetCustomAttributeOrThrow<T>(this MemberInfo member, bool inherit) where T : Attribute
		{
			object[] customAttributes = member.GetCustomAttributes(typeof(T), inherit);
			if (customAttributes.Length == 0)
			{
				throw new ArgumentOutOfRangeException("T", $"{member} has no attribute {typeof(T)}");
			}
			if (customAttributes.Length > 1)
			{
				throw new InvalidOperationException($"{member} has more than one attribute {typeof(T)}");
			}
			return (T)customAttributes[0];
		}

		public static NetworkBehaviourWeavedAttribute GetWeavedAttributeOrThrow(Type type)
		{
			try
			{
				return type.GetCustomAttributeOrThrow<NetworkBehaviourWeavedAttribute>(inherit: false);
			}
			catch (ArgumentOutOfRangeException)
			{
				throw new InvalidOperationException(string.Format("Type {0} has not been weaved. Has the assembly {1} been added to {2}?", type, type.Assembly.GetName().Name, "NetworkProjectConfig"));
			}
		}

		public static IEnumerable<Assembly> GetAllWeavedAssemblies()
		{
			Assembly[] assemblies = AppDomain.CurrentDomain.GetAssemblies();
			foreach (Assembly asm in assemblies)
			{
				NetworkAssemblyWeavedAttribute attr = asm.GetCustomAttribute<NetworkAssemblyWeavedAttribute>();
				if (attr != null)
				{
					yield return asm;
				}
			}
		}

		public static IEnumerable<Type> GetAllSimulationBehaviourTypes()
		{
			Assembly[] assemblies = AppDomain.CurrentDomain.GetAssemblies();
			foreach (Assembly asm in assemblies)
			{
				Type[] types = asm.GetTypes();
				foreach (Type type in types)
				{
					if (typeof(SimulationBehaviour).IsAssignableFrom(type))
					{
						yield return type;
					}
				}
			}
		}

		public static IEnumerable<Type> GetAllWeavedSimulationBehaviourTypes()
		{
			foreach (Assembly asm in GetAllWeavedAssemblies())
			{
				Type[] types = asm.GetTypes();
				foreach (Type type in types)
				{
					if (typeof(SimulationBehaviour).IsAssignableFrom(type))
					{
						yield return type;
					}
				}
			}
		}

		public static IEnumerable<Type> GetAllNetworkBehaviourTypes()
		{
			foreach (Type type in GetAllSimulationBehaviourTypes())
			{
				if (typeof(NetworkBehaviour).IsAssignableFrom(type))
				{
					yield return type;
				}
			}
		}

		public static IEnumerable<Type> GetAllWeavedNetworkBehaviourTypes()
		{
			foreach (Type type in GetAllWeavedSimulationBehaviourTypes())
			{
				if (typeof(NetworkBehaviour).IsAssignableFrom(type))
				{
					yield return type;
				}
			}
		}

		public static IEnumerable<Type> GetAllWeaverGeneratedTypes()
		{
			foreach (Assembly asm in GetAllWeavedAssemblies())
			{
				Type[] types = asm.GetTypes();
				foreach (Type type in types)
				{
					WeaverGeneratedAttribute weaverGen = type.GetCustomAttribute<WeaverGeneratedAttribute>();
					if (weaverGen != null)
					{
						yield return type;
					}
				}
			}
		}
	}
	internal class RingBuffer<T> : IEnumerable<T>, IEnumerable where T : struct
	{
		private readonly T[] _buffer;

		private int _front;

		private int _count;

		public int Count => _count;

		public int Capacity => _buffer.Length;

		public bool IsEmpty => _count == 0;

		public bool IsFull => _count == _buffer.Length;

		public T this[int index]
		{
			get
			{
				if (IsEmpty)
				{
					throw new IndexOutOfRangeException($"Cannot access index {index}. Buffer is empty.");
				}
				if (index >= _count)
				{
					throw new IndexOutOfRangeException($"Cannot access index {index}. Buffer has {_count} items.");
				}
				int num = InternalIndex(index);
				return _buffer[num];
			}
			set
			{
				if (IsEmpty)
				{
					throw new IndexOutOfRangeException($"Cannot access index {index}. Buffer is empty.");
				}
				if (index >= _count)
				{
					throw new IndexOutOfRangeException($"Cannot access index {index}. Buffer has {_count} items.");
				}
				int num = InternalIndex(index);
				_buffer[num] = value;
			}
		}

		public RingBuffer(int capacity)
			: this(capacity, new T[0])
		{
		}

		public RingBuffer(int capacity, T[] items)
		{
			if (capacity < 1)
			{
				throw new ArgumentException("Buffer cannot have negative or zero capacity.", "capacity");
			}
			if (items == null)
			{
				throw new ArgumentNullException("items");
			}
			if (items.Length > capacity)
			{
				throw new ArgumentException("Number of items exceeds buffer capacity.", "items");
			}
			_buffer = new T[capacity];
			Array.Copy(items, _buffer, items.Length);
			_front = 0;
			_count = items.Length;
		}

		public ref readonly T Front()
		{
			ThrowIfEmpty();
			return ref _buffer[_front];
		}

		public ref T FrontMut()
		{
			ThrowIfEmpty();
			return ref _buffer[_front];
		}

		public ref readonly T Get(int index)
		{
			if (IsEmpty)
			{
				throw new IndexOutOfRangeException($"Cannot access index {index}. Buffer is empty.");
			}
			if (index >= _count)
			{
				throw new IndexOutOfRangeException($"Cannot access index {index}. Buffer has {_count} items.");
			}
			int num = InternalIndex(index);
			return ref _buffer[num];
		}

		public ref T GetMut(int index)
		{
			if (IsEmpty)
			{
				throw new IndexOutOfRangeException($"Cannot access index {index}. Buffer is empty.");
			}
			if (index >= _count)
			{
				throw new IndexOutOfRangeException($"Cannot access index {index}. Buffer has {_count} items.");
			}
			int num = InternalIndex(index);
			return ref _buffer[num];
		}

		public ref readonly T Back()
		{
			ThrowIfEmpty();
			int num = Decrement(BackIndex());
			return ref _buffer[num];
		}

		public ref T BackMut()
		{
			ThrowIfEmpty();
			int num = Decrement(BackIndex());
			return ref _buffer[num];
		}

		public void PushBack(T item)
		{
			int num = BackIndex();
			if (IsFull)
			{
				_buffer[num] = item;
				_front = Increment(num);
			}
			else
			{
				_buffer[num] = item;
				_count++;
			}
		}

		public void PushFront(T item)
		{
			_front = Decrement(_front);
			if (IsFull)
			{
				_buffer[_front] = item;
				return;
			}
			_buffer[_front] = item;
			_count++;
		}

		public T PopBack()
		{
			ThrowIfEmpty("Cannot take items from an empty buffer.");
			int num = Decrement(BackIndex());
			T result = _buffer[num];
			_buffer[num] = default(T);
			_count--;
			return result;
		}

		public T PopFront()
		{
			ThrowIfEmpty("Cannot take items from an empty buffer.");
			T result = _buffer[_front];
			_buffer[_front] = default(T);
			_front = Increment(_front);
			_count--;
			return result;
		}

		public void Clear()
		{
			_front = 0;
			_count = 0;
			Array.Clear(_buffer, 0, _buffer.Length);
		}

		public IList<ArraySegment<T>> ToArraySegments()
		{
			return new ArraySegment<T>[2]
			{
				SpanOne(),
				SpanTwo()
			};
		}

		public T[] ToArray()
		{
			T[] array = new T[Count];
			int num = 0;
			IList<ArraySegment<T>> list = ToArraySegments();
			foreach (ArraySegment<T> item in list)
			{
				Array.Copy(item.Array, item.Offset, array, num, item.Count);
				num += item.Count;
			}
			return array;
		}

		public IEnumerator<T> GetEnumerator()
		{
			IList<ArraySegment<T>> segments = ToArraySegments();
			foreach (ArraySegment<T> segment in segments)
			{
				for (int i = 0; i < segment.Count; i++)
				{
					yield return segment.Array[segment.Offset + i];
				}
			}
		}

		IEnumerator IEnumerable.GetEnumerator()
		{
			return GetEnumerator();
		}

		private int FrontIndex()
		{
			return _front;
		}

		private int BackIndex()
		{
			return (_front + _count) % Capacity;
		}

		private int InternalIndex(int index)
		{
			return (_front + index) % Capacity;
		}

		private int Increment(int index)
		{
			Assert.Check(index >= 0 && index < Capacity);
			return (index != Capacity - 1) ? (index + 1) : 0;
		}

		private int Decrement(int index)
		{
			Assert.Check(index >= 0 && index < Capacity);
			return (index == 0) ? (Capacity - 1) : (index - 1);
		}

		private void ThrowIfEmpty(string message = "Cannot access an empty buffer.")
		{
			if (IsEmpty)
			{
				throw new InvalidOperationException(message);
			}
		}

		private ArraySegment<T> SpanOne()
		{
			int num = BackIndex();
			if (IsEmpty)
			{
				return new ArraySegment<T>(new T[0]);
			}
			if (_front < num)
			{
				return new ArraySegment<T>(_buffer, _front, num - _front);
			}
			return new ArraySegment<T>(_buffer, _front, _buffer.Length - _front);
		}

		private ArraySegment<T> SpanTwo()
		{
			int num = BackIndex();
			if (IsEmpty)
			{
				return new ArraySegment<T>(new T[0]);
			}
			if (_front < num)
			{
				return new ArraySegment<T>(_buffer, num, 0);
			}
			return new ArraySegment<T>(_buffer, 0, num);
		}
	}
	[Serializable]
	[StructLayout(LayoutKind.Explicit)]
	[NetworkStructWeaved(1)]
	public struct SceneRef : INetworkStruct, IEquatable<SceneRef>
	{
		public const int SIZE = 4;

		public const uint FLAG_ADDRESSABLE = 2147483648u;

		[FieldOffset(0)]
		public uint RawValue;

		public static SceneRef None => default(SceneRef);

		public bool IsValid => RawValue != 0;

		public bool IsIndex => (RawValue & 0x80000000u) == 0;

		public int AsIndex
		{
			get
			{
				if (!IsIndex)
				{
					throw new InvalidOperationException($"SceneRef {RawValue:X8} is not an index");
				}
				return (int)(RawValue - 1);
			}
		}

		public uint AsPathHash
		{
			get
			{
				if (IsIndex)
				{
					throw new InvalidOperationException($"SceneRef {RawValue:X8} is not a path hash");
				}
				return RawValue & 0x7FFFFFFF;
			}
		}

		public bool IsPath(string path)
		{
			if (IsIndex)
			{
				return false;
			}
			return this == FromPath(path);
		}

		public static SceneRef FromIndex(int index)
		{
			if (index < 0 || index == int.MaxValue)
			{
				throw new ArgumentOutOfRangeException("index");
			}
			SceneRef result = default(SceneRef);
			result.RawValue = (uint)(index + 1);
			return result;
		}

		public static SceneRef FromPath(string path)
		{
			uint hashCodeDeterministic = (uint)HashCodeUtilities.GetHashCodeDeterministic(path ?? throw new ArgumentNullException("path"));
			hashCodeDeterministic &= 0x7FFFFFFF;
			SceneRef result = default(SceneRef);
			result.RawValue = 0x80000000u | hashCodeDeterministic;
			return result;
		}

		public static SceneRef FromRaw(uint rawValue)
		{
			SceneRef result = default(SceneRef);
			result.RawValue = rawValue;
			return result;
		}

		public override bool Equals(object obj)
		{
			return obj is SceneRef other && Equals(other);
		}

		public bool Equals(SceneRef other)
		{
			return RawValue == other.RawValue;
		}

		public override int GetHashCode()
		{
			return RawValue.GetHashCode();
		}

		public override string ToString()
		{
			return ToString(brackets: true, prefix: true);
		}

		public string ToString(bool brackets, bool prefix)
		{
			StringBuilder stringBuilder = new StringBuilder();
			if (brackets)
			{
				stringBuilder.Append('[');
			}
			if (prefix)
			{
				stringBuilder.Append("Scene:");
			}
			if (IsValid)
			{
				if (IsIndex)
				{
					stringBuilder.Append("#").Append(AsIndex);
				}
				else
				{
					stringBuilder.AppendFormat("0x{0:X8}", AsPathHash);
				}
			}
			else
			{
				stringBuilder.Append("None");
			}
			if (brackets)
			{
				stringBuilder.Append(']');
			}
			return stringBuilder.ToString();
		}

		public static SceneRef Parse(string str)
		{
			ReadOnlySpan<char> span = MemoryExtensions.AsSpan(str);
			if (span.StartsWith("["))
			{
				if (!span.EndsWith("]"))
				{
					throw new FormatException("Invalid SceneRef format: " + str);
				}
				span = span.Slice(1, span.Length - 2);
			}
			if (span.StartsWith("Scene:"))
			{
				span = span.Slice(6);
			}
			if (span.StartsWith("#"))
			{
				return FromIndex(int.Parse(span.Slice(1)));
			}
			if (span.StartsWith("0x"))
			{
				return FromRaw(uint.Parse(span.Slice(2), NumberStyles.HexNumber) | 0x80000000u);
			}
			if (span.SequenceEqual(MemoryExtensions.AsSpan("None")))
			{
				return None;
			}
			throw new FormatException("Invalid SceneRef format: " + str);
		}

		public static bool operator ==(SceneRef a, SceneRef b)
		{
			return a.RawValue == b.RawValue;
		}

		public static bool operator !=(SceneRef a, SceneRef b)
		{
			return a.RawValue != b.RawValue;
		}
	}
	public abstract class SerializableDictionary
	{
		public static SerializableDictionary<TKey, TValue> Create<TKey, TValue>()
		{
			return new SerializableDictionary<TKey, TValue>();
		}
	}
	[Serializable]
	public class SerializableDictionary<TKey, TValue> : SerializableDictionary, IDictionary<TKey, TValue>, ICollection<KeyValuePair<TKey, TValue>>, IEnumerable<KeyValuePair<TKey, TValue>>, IEnumerable, ISerializationCallbackReceiver
	{
		[Serializable]
		private struct Entry
		{
			public TKey Key;

			public TValue Value;
		}

		public const string ItemsPropertyPath = "_items";

		public const string EntryKeyPropertyPath = "Key";

		[SerializeField]
		private Entry[] _items;

		[NonSerialized]
		private List<(Entry, int)> _duplicatesAndNulls;

		[NonSerialized]
		private Dictionary<TKey, TValue> _dictionary;

		private Dictionary<TKey, TValue> Inner
		{
			[MethodImpl(MethodImplOptions.AggressiveInlining)]
			get
			{
				if (_dictionary == null)
				{
					_dictionary = CreateDictionary();
				}
				return _dictionary;
			}
		}

		private ICollection<KeyValuePair<TKey, TValue>> DictionaryAsCollection => Inner;

		public TValue this[TKey key]
		{
			get
			{
				return Inner[key];
			}
			set
			{
				Inner[key] = value;
			}
		}

		public int Count => Inner.Count;

		public bool IsReadOnly => false;

		public Dictionary<TKey, TValue>.KeyCollection Keys => Inner.Keys;

		public Dictionary<TKey, TValue>.ValueCollection Values => Inner.Values;

		ICollection<TKey> IDictionary<TKey, TValue>.Keys => Inner.Keys;

		ICollection<TValue> IDictionary<TKey, TValue>.Values => Inner.Values;

		public static SerializableDictionary<TKey, TValue> Wrap(Dictionary<TKey, TValue> dictionary)
		{
			return new SerializableDictionary<TKey, TValue>
			{
				_dictionary = dictionary
			};
		}

		public void Add(TKey key, TValue value)
		{
			Inner.Add(key, value);
		}

		public virtual void Clear()
		{
			_duplicatesAndNulls?.Clear();
			Inner.Clear();
		}

		public bool ContainsKey(TKey key)
		{
			return Inner.ContainsKey(key);
		}

		public bool Remove(TKey key)
		{
			return Inner.Remove(key);
		}

		public bool TryGetValue(TKey key, out TValue value)
		{
