					TKey key = item.Key;
					TValue value = item.Value;
					TKey val = key;
					if ((flag && dictionary.Comparer.Equals(val, default(TKey))) || dictionary.ContainsKey(val))
					{
						if (_duplicatesAndNulls == null)
						{
							_duplicatesAndNulls = new List<(Entry, int)>();
						}
						_duplicatesAndNulls.Add((item, i));
					}
					else
