			}
			if (_duplicatesAndNulls == null)
			{
				return;
			}
			foreach (var duplicatesAndNull in _duplicatesAndNulls)
			{
				for (int num3 = num2 - 1; num3 > duplicatesAndNull.Item2; num3--)
				{
					_items[num3] = _items[num3 - 1];
