	public struct TickAccumulator
	{
		private double _time;

		private double _scale;

		private int _ticks;

		private bool _running;

		public int Pending => _ticks;

		public double Remainder => _time;

		public bool Running => _running;

		public double TimeScale
		{
			get
			{
				return _scale;
			}
			set
			{
				Assert.Check(value > 0.0);
				_scale = value;
			}
		}

		public float Alpha(double step)
		{
			return (float)Maths.Clamp01((double)_ticks / step);
		}

		public void AddTicks(int ticks)
		{
			_ticks += ticks;
		}

		public void AddTime(double dt, double step, int? maxTicks = null)
		{
			Assert.Check(dt >= 0.0);
			Assert.Check(step > 0.0);
			if (!_running)
			{
				return;
			}
			Assert.Check(_scale > 0.0);
			Assert.Check(!double.IsInfinity(dt));
			_time += dt * _scale;
			while (_time >= step)
			{
				_time -= step;
				_ticks++;
				if (maxTicks.HasValue && _ticks >= maxTicks.Value)
				{
					_time = 0.0;
					_ticks = maxTicks.Value;
					break;
				}
			}
		}

		public void Stop()
		{
			_running = false;
		}

		public void Start()
		{
			_running = true;
		}

		public bool ConsumeTick(out bool last)
		{
			Assert.Check(_ticks >= 0);
			if (_ticks > 0)
			{
				_ticks--;
				last = _ticks == 0;
				return true;
			}
			last = false;
			return false;
		}

		public static TickAccumulator StartNew()
		{
			TickAccumulator result = default(TickAccumulator);
			result.TimeScale = 1.0;
			result.Start();
			return result;
		}
	}
	[StructLayout(LayoutKind.Explicit)]
	public struct TickRate
	{
		[Serializable]
		[StructLayout(LayoutKind.Explicit)]
		public struct Selection
		{
			[FieldOffset(0)]
			public int Client;

			[FieldOffset(4)]
			public int ServerIndex;

			[FieldOffset(8)]
			public int ClientSendIndex;

			[FieldOffset(12)]
			public int ServerSendIndex;
		}

		[StructLayout(LayoutKind.Explicit)]
		public struct Resolved
		{
			public const int SIZE = 16;

			public const int WORDS = 4;

			[FieldOffset(0)]
			public int Client;

			[FieldOffset(4)]
			public int ClientSend;

			[FieldOffset(8)]
			public int Server;

			[FieldOffset(12)]
			public int ServerSend;

			public double ServerTickDelta => Inverse(Server);

			public double ServerSendDelta => Inverse(ServerSend);

			public int ServerTickStride => Client / Server;

			public double ClientTickDelta => Inverse(Client);

			public double ClientSendDelta => Inverse(ClientSend);

			public int ClientTickStride => 1;

			internal Resolved(int client, int clientSend, int server, int serverSend)
			{
				Client = client;
				ClientSend = clientSend;
				Server = server;
				ServerSend = serverSend;
			}

			public override string ToString()
			{
				return $"[ClientTickRate = {Client}, ClientSendRate = {ClientSend}, ServerTickRate = {Server}, ServerSendRate = {ServerSend}]";
			}

			[MethodImpl(MethodImplOptions.AggressiveInlining)]
			private static double Inverse(int rate)
			{
				return (rate == 0) ? 0.0 : (1.0 / (double)rate);
			}
		}

		public enum ValidateResult
		{
			Ok,
			Error,
			NotFound,
			InvalidTickRate,
			ServerIndexOutOfRange,
			ClientSendIndexOutOfRange,
			ServerSendIndexOutOfRange,
			ServerSendRateLargerThanTickRate
		}

		[FieldOffset(0)]
		private int _count;

		[FieldOffset(4)]
		private unsafe fixed int _rates[4];

		private static TickRate[] _valid;

		private static ReadOnlyCollection<TickRate> _validReadOnly;

		private static Dictionary<int, TickRate> _lookup;

		public unsafe int Client => _rates[0];

		public int Count => _count;

		public int this[int index] => GetTickRate(index);

		internal static Selection Default => new Selection
		{
			Client = 64,
			ClientSendIndex = 1,
			ServerIndex = 0,
			ServerSendIndex = 1
		};

		internal static Selection Shared => new Selection
		{
			Client = 32,
			ClientSendIndex = 1,
			ServerIndex = 0,
			ServerSendIndex = 1
		};

		public static IReadOnlyList<TickRate> Available
		{
			get
			{
				InitChecked();
				return _validReadOnly;
			}
		}

		private unsafe TickRate(params int[] rates)
		{
			Assert.Check(rates.Length >= 1 && rates.Length <= 4);
			_count = rates.Length;
			for (int i = 0; i < rates.Length; i++)
			{
				_rates[i] = rates[i];
			}
		}

		public int GetDivisor(int index)
		{
			Assert.Check((uint)index < _count);
			Assert.Check(Client == Client / GetTickRate(index) * GetTickRate(index));
			return Client / GetTickRate(index);
		}

		public unsafe int GetTickRate(int index)
		{
			Assert.Check((uint)index < _count);
			return _rates[index];
		}

		public int[] ToArray()
		{
			int[] array = new int[_count];
			for (int i = 0; i < array.Length; i++)
			{
				array[i] = GetTickRate(i);
			}
			return array;
		}

		private unsafe bool Validate()
		{
			if (_count == 0)
			{
				return false;
			}
			if (_count > 4)
			{
				return false;
			}
			if (_rates[0] <= 0)
			{
				return false;
			}
			for (int i = 1; i < _count; i++)
			{
				if (_rates[0] != _rates[0] / GetTickRate(i) * GetTickRate(i))
				{
					return false;
				}
			}
			return true;
		}

		public Selection ClampSelection(Selection selection)
		{
			if (!Validate())
			{
				return default(Selection);
			}
			selection.ServerIndex = Maths.Clamp(selection.ServerIndex, 0, _count - 1);
			selection.ServerSendIndex = Maths.Clamp(selection.ServerSendIndex, selection.ServerIndex, _count - 1);
			selection.ClientSendIndex = Maths.Clamp(selection.ClientSendIndex, 0, _count - 1);
			return selection;
		}

		public ValidateResult ValidateSelection(Selection selected)
		{
			if (!Validate())
			{
				return ValidateResult.InvalidTickRate;
			}
			if (Client != selected.Client)
			{
				return ValidateResult.Error;
			}
			if ((uint)selected.ServerIndex >= (uint)_count)
			{
				return ValidateResult.ServerIndexOutOfRange;
			}
			if ((uint)selected.ServerSendIndex >= (uint)_count)
			{
				return ValidateResult.ServerSendIndexOutOfRange;
			}
			if ((uint)selected.ClientSendIndex >= (uint)_count)
			{
				return ValidateResult.ClientSendIndexOutOfRange;
			}
			if (selected.ServerSendIndex < selected.ServerIndex)
			{
				return ValidateResult.ServerSendRateLargerThanTickRate;
			}
			return ValidateResult.Ok;
		}

		static TickRate()
		{
			Init();
		}

		private static void InitChecked()
		{
			if (_valid == null || _valid.Length == 0 || _lookup == null || _lookup.Count <= 0)
			{
				Init();
			}
		}

		public static void Init()
		{
			_valid = new TickRate[15]
			{
				new TickRate(8, 4),
				new TickRate(10, 5),
				new TickRate(16, 8, 4),
				new TickRate(20, 10, 5),
				new TickRate(24, 12, 6),
				new TickRate(30, 15),
				new TickRate(32, 16, 8),
				new TickRate(50, 25),
				new TickRate(60, 30, 15),
				new TickRate(64, 32, 16),
				new TickRate(100, 50, 25),
				new TickRate(120, 60, 30),
				new TickRate(128, 64, 32),
				new TickRate(240, 120, 60, 30),
				new TickRate(256, 128, 64, 32)
			};
			_validReadOnly = new ReadOnlyCollection<TickRate>(_valid);
			_lookup = new Dictionary<int, TickRate>();
			TickRate[] valid = _valid;
			for (int i = 0; i < valid.Length; i++)
			{
				TickRate value = valid[i];
				_lookup.Add(value.Client, value);
			}
		}

		public static bool IsValid(TickRate rate)
		{
			return IsValid(rate.Client);
		}

		public static bool IsValid(int rate)
		{
			InitChecked();
			return _lookup.ContainsKey(rate);
		}

		public static TickRate Get(int rate)
		{
			InitChecked();
			if (_lookup.TryGetValue(rate, out var value))
			{
				return value;
			}
			throw new InvalidOperationException("invalid tickrate");
		}

		public static Resolved Resolve(Selection selection)
		{
			InitChecked();
			Assert.Always(IsValid(selection.Client), "IsValid(selection.Client)");
			TickRate tickRate = _lookup[selection.Client];
			ValidateResult validateResult = tickRate.ValidateSelection(selection);
			Assert.Always(validateResult == ValidateResult.Ok, "result != ValidateResult.Ok");
			return new Resolved(tickRate.Client, tickRate.GetTickRate(selection.ClientSendIndex), tickRate.GetTickRate(selection.ServerIndex), tickRate.GetTickRate(selection.ServerSendIndex));
		}
	}
	[StructLayout(LayoutKind.Explicit)]
	[NetworkStructWeaved(1)]
	public struct TickTimer : INetworkStruct
	{
		[FieldOffset(0)]
		private int _target;

		public static TickTimer None => default(TickTimer);

		public bool IsRunning => _target > 0;

		public int? TargetTick => (_target > 0) ? _target : 0;

		public bool Expired(NetworkRunner runner)
		{
			return BehaviourUtils.IsAlive(runner) && runner.IsRunning && _target > 0 && _target <= runner.Simulation.Tick;
		}

		public bool ExpiredOrNotRunning(NetworkRunner runner)
		{
			return _target == 0 || !runner.IsRunning || Expired(runner);
		}

		public int? RemainingTicks(NetworkRunner runner)
		{
			if (BehaviourUtils.IsNotAlive(runner) || !runner.IsRunning)
			{
				return null;
			}
			if (IsRunning)
			{
				return Math.Max(0, _target - (int)runner.Simulation.Tick);
			}
			return null;
		}

		public float? RemainingTime(NetworkRunner runner)
		{
			int? num = RemainingTicks(runner);
			if (num.HasValue)
			{
				return (float)num.Value * runner.DeltaTime;
			}
			return null;
		}

		public static TickTimer CreateFromSeconds(NetworkRunner runner, float delayInSeconds)
		{
			if (BehaviourUtils.IsNotAlive(runner) || !runner.IsRunning)
			{
				return default(TickTimer);
			}
			TickTimer result = default(TickTimer);
			result._target = (int)runner.Simulation.Tick + (int)Math.Ceiling(delayInSeconds / runner.DeltaTime);
			return result;
		}

		public static TickTimer CreateFromTicks(NetworkRunner runner, int ticks)
		{
			if (BehaviourUtils.IsNotAlive(runner) || !runner.IsRunning)
			{
				return default(TickTimer);
			}
			TickTimer result = default(TickTimer);
			result._target = (int)runner.Simulation.Tick + ticks;
			return result;
		}

		public override string ToString()
		{
			return _target.ToString();
		}
	}
	internal class TimeSeries
	{
		private double _mean;

		private double _varSum;

		private readonly RingBuffer<double> _samples;

		public int Count => _samples.Count;

		public int Capacity => _samples.Capacity;

		public bool IsEmpty => _samples.IsEmpty;

		public bool IsFull => _samples.IsFull;

		public double Latest => IsEmpty ? 0.0 : _samples.Back();

		public double Avg => _mean;

		public double Var
		{
			get
			{
				if (Count > 1 && _varSum >= 0.0)
				{
					return _varSum / (double)(Count - 1);
				}
				return 0.0;
			}
		}

		public double Dev
		{
			get
			{
				double var = Var;
				return (var >= double.Epsilon) ? Math.Sqrt(var) : 0.0;
			}
		}

		public double Min
		{
			get
			{
				double num = 0.0;
				for (int i = 0; i < Count; i++)
				{
					num = Math.Min(num, _samples[i]);
				}
				return num;
			}
		}

		public double Max
		{
			get
			{
				double num = 0.0;
				for (int i = 0; i < Count; i++)
				{
					num = Math.Max(num, _samples[i]);
				}
				return num;
			}
		}

		public double Median => FindMedian(_samples);

		public double MeanAbsDev
		{
			get
			{
				double mean = _mean;
				double num = 0.0;
				for (int i = 0; i < Count; i++)
				{
					num += Math.Abs(_samples[i] - mean);
				}
				return 1.2533 * (num / (double)Count);
			}
		}

		public double MedianAbsDev
		{
			get
			{
				double median = Median;
				List<double> list = new List<double>(Count);
				for (int i = 0; i < Count; i++)
				{
					list.Add(Math.Abs(_samples[i] - median));
				}
				return 1.4826 * FindMedian(list);
			}
		}

		public double Smoothed(double alpha)
		{
			Assert.Check(alpha >= 0.0 && alpha <= 1.0, "the input range of this method is [0.0, 1.0], inclusive");
			if (Count > 0)
			{
				double num = _samples[0];
				for (int i = 1; i < Count; i++)
				{
					num = (1.0 - alpha) * num + alpha * _samples[i];
				}
				return num;
			}
			return 0.0;
		}

		public TimeSeries(int capacity)
		{
			_mean = 0.0;
			_varSum = 0.0;
			_samples = new RingBuffer<double>(Math.Max(2, capacity));
		}

		public void Add(double value)
		{
			Assert.Check(!double.IsNaN(value));
			Assert.Check(!double.IsInfinity(value));
			double mean = _mean;
			if (IsFull)
			{
				double num = _samples.PopFront();
				_samples.PushBack(value);
				double num2 = value - num;
				_mean += num2 / (double)Capacity;
				_varSum += num2 * (value - _mean + (num - mean));
			}
			else
			{
				_samples.PushBack(value);
				double num3 = value - mean;
				_mean += num3 / (double)Count;
				_varSum += num3 * (value - _mean);
			}
		}

		public void Fill(double value)
		{
			Clear();
			for (int i = 0; i < Capacity; i++)
			{
				Add(value);
			}
		}

		public double QuantileNormal(double p)
		{
			return Avg + InverseCdfNormal(p) * Dev;
		}

		public static double InverseCdfNormal(double p)
		{
			Assert.Check(p > 0.0 && p < 1.0, "the input range of this function is (0.0, 1.0), non-inclusive");
			if (p < 0.5)
			{
				return 0.0 - Polynomial(p);
			}
			return Polynomial(1.0 - p);
			static double Polynomial(double x)
			{
				double num = Math.Sqrt(-2.0 * Math.Log(x));
				double num2 = (0.06114673576519699 * num + 1.5615337002120804) * num + 2.6539620026016846;
				double num3 = ((0.009547745327068945 * num + 0.4540555364442335) * num + 1.9048751828364987) * num + 1.0;
				return num - num2 / num3;
			}
		}

		internal static double FindMedian(IEnumerable<double> values)
		{
			return FindMedian(new List<double>(values));
		}

		internal static double FindMedian(List<double> list)
		{
			int count = list.Count;
			if (count == 0)
			{
				return 0.0;
			}
			list.Sort();
			if (count % 2 == 1)
			{
				return list[count / 2];
			}
			return 0.5 * (list[count / 2 - 1] + list[count / 2]);
		}

		public void Clear()
		{
			_mean = 0.0;
			_varSum = 0.0;
			_samples.Clear();
		}
	}
