	[StructLayout(LayoutKind.Explicit)]
	public struct RpcHeader
	{
		public const int SIZE = 8;

		[FieldOffset(0)]
		public NetworkId Object;

		[FieldOffset(4)]
		public ushort Behaviour;

		[FieldOffset(6)]
		public ushort Method;

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		[Obsolete("No longer used")]
		public unsafe static int Write(RpcHeader header, byte* data)
		{
			*(RpcHeader*)data = header;
			return 8;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		[Obsolete("No longer used")]
		public unsafe static int ReadSize(byte* data)
		{
			return 8;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		[Obsolete("No longer used")]
		public unsafe static RpcHeader Read(byte* data, out int size)
		{
			size = 8;
			return *(RpcHeader*)data;
		}

		public unsafe static RpcHeader Create(NetworkId id, int behaviour, int method)
		{
			Assert.Check(sizeof(RpcHeader) == 8);
			RpcHeader result = default(RpcHeader);
			result.Object = id;
			result.Behaviour = (ushort)behaviour;
			result.Method = (ushort)method;
			return result;
		}

		public unsafe static RpcHeader Create(int staticRpcKey)
		{
			Assert.Check(sizeof(RpcHeader) == 8);
			RpcHeader result = default(RpcHeader);
			result.Object = default(NetworkId);
			result.Behaviour = 0;
			result.Method = (ushort)staticRpcKey;
			return result;
		}

		public override string ToString()
		{
			return string.Format("[RpcHeader: {0}={1}, {2}={3}, {4}={5}]", "Object", Object, "Behaviour", Behaviour, "Method", Method);
		}
	}
	public enum RpcHostMode
	{
		SourceIsServer,
		SourceIsHostPlayer
	}
	public struct RpcInfo
	{
		public Tick Tick;

		public PlayerRef Source;

		public RpcChannel Channel;

		public bool IsInvokeLocal;

		public static RpcInfo FromLocal(NetworkRunner runner, RpcChannel channel, RpcHostMode hostMode)
		{
			RpcInfo result = new RpcInfo
			{
				Tick = runner.Simulation.Tick,
				Source = runner.Simulation.LocalPlayer,
				IsInvokeLocal = true,
				Channel = channel
			};
			if (hostMode == RpcHostMode.SourceIsServer && runner.Simulation.IsHostPlayer(result.Source) && !runner.IsSinglePlayer)
			{
				result.Source = default(PlayerRef);
			}
			return result;
		}

		public unsafe static RpcInfo FromMessage(NetworkRunner runner, SimulationMessage* message, RpcHostMode hostMode)
		{
			RpcInfo result = new RpcInfo
			{
				Tick = message->Tick,
				Source = message->Source,
				IsInvokeLocal = false,
				Channel = (message->GetFlag(8) ? RpcChannel.Unreliable : RpcChannel.Reliable)
			};
			if (message->Source.IsNone && hostMode == RpcHostMode.SourceIsHostPlayer && runner.Simulation.TryGetHostPlayer(out var player))
			{
				result.Source = player;
			}
			return result;
		}

		public override string ToString()
		{
			return string.Format("[RpcInfo: {0}={1}, {2}={3}, {4}={5}, {6}={7}]", "Tick", Tick, "Source", Source, "IsInvokeLocal", IsInvokeLocal, "Channel", Channel);
		}
	}
