		[NonSerialized]
		internal readonly Dictionary<Type, int> ExecutionOrderOverrides = new Dictionary<Type, int>();

		public static NetworkProjectConfig Global => NetworkProjectConfigAsset.Global.Config;

		public static (NetworkRunner.BuildTypes, FileVersionInfo) FusionVersionInfo
		{
			get
			{
				Assembly[] assemblies = AppDomain.CurrentDomain.GetAssemblies();
				foreach (Assembly assembly in assemblies)
				{
					string fullName = assembly.FullName;
					if (fullName.StartsWith("Fusion.Runtime,"))
					{
						return (NetworkRunner.BuildType, FileVersionInfo.GetVersionInfo(assembly.Location));
					}
				}
				return ((NetworkRunner.BuildTypes)(-1), null);
			}
		}

		public static void UnloadGlobal()
		{
			NetworkProjectConfigAsset.UnloadGlobal();
		}

		public int? GetExecutionOrder(Type type)
		{
			if (ExecutionOrderOverrides.TryGetValue(type, out var value))
			{
				return value;
			}
			while (type != typeof(object))
			{
				DefaultExecutionOrder customAttribute = type.GetCustomAttribute<DefaultExecutionOrder>();
				if (customAttribute != null)
				{
					return customAttribute.order;
				}
				type = type.BaseType;
			}
			return null;
		}

		internal NetworkProjectConfig Init(int globalSize, int? playerCountOverride, int? inputWordCount)
		{
			NetworkProjectConfig networkProjectConfig = Copy();
			networkProjectConfig.Heap = networkProjectConfig.Heap.Init(globalSize);
			networkProjectConfig.Network = networkProjectConfig.Network.Init();
			networkProjectConfig.Simulation = networkProjectConfig.Simulation.Init(playerCountOverride, inputWordCount);
			return networkProjectConfig;
		}

		internal NetworkProjectConfig Copy()
		{
			NetworkProjectConfig networkProjectConfig = (NetworkProjectConfig)MemberwiseClone();
			networkProjectConfig.Simulation = Simulation.Copy();
			return networkProjectConfig;
		}

		public override string ToString()
		{
			return Serialize(this);
		}

		public static string Serialize(NetworkProjectConfig config)
		{
			return JsonUtility.ToJson(config);
		}

		public static NetworkProjectConfig Deserialize(string data)
		{
			return JsonUtility.FromJson<NetworkProjectConfig>(data);
		}

		internal static string SerializeMinimal(NetworkProjectConfig config)
		{
			return JsonUtils.RemoveExtraReferences(Serialize(config));
		}
	}
	[ScriptHelp]
	[FusionGlobalScriptableObject("Assets/Photon/Fusion/Resources/NetworkProjectConfig.fusion", DefaultContentsGeneratorMethod = "GenerateDefaultContents")]
	public class NetworkProjectConfigAsset : FusionGlobalScriptableObject<NetworkProjectConfigAsset>
	{
		[Serializable]
		public struct SerializableSimulationBehaviourMeta
		{
			public SerializableType<SimulationBehaviour> Type;

			public int ExecutionOrder;
		}

		[SerializeField]
		[DrawInline]
		public NetworkProjectConfig Config = new NetworkProjectConfig();

		[ResolveNetworkPrefabSource]
		[SerializeReference]
		[HideArrayElementLabel]
		[InlineHelp]
		public List<INetworkPrefabSource> Prefabs = new List<INetworkPrefabSource>();

		public NetworkPrefabTableOptions PrefabOptions = NetworkPrefabTableOptions.Default;

		[ReadOnly]
		[InlineHelp]
		[SerializeField]
		public SerializableSimulationBehaviourMeta[] BehaviourMeta = Array.Empty<SerializableSimulationBehaviourMeta>();

		public static NetworkProjectConfigAsset Global => FusionGlobalScriptableObject<NetworkProjectConfigAsset>.GlobalInternal;

		public static bool IsGlobalLoaded => FusionGlobalScriptableObject<NetworkProjectConfigAsset>.IsGlobalLoadedInternal;

		public static bool TryGetGlobal(out NetworkProjectConfigAsset global)
		{
			return FusionGlobalScriptableObject<NetworkProjectConfigAsset>.TryGetGlobalInternal(out global);
		}

		public static void UnloadGlobal()
		{
			FusionGlobalScriptableObject<NetworkProjectConfigAsset>.UnloadGlobalInternal();
		}

		private void OnEnable()
		{
			Config.PrefabTable.Clear();
			Config.ExecutionOrderOverrides.Clear();
			NetworkPrefabTable prefabTable = Config.PrefabTable;
			foreach (INetworkPrefabSource prefab in Prefabs)
			{
				if (!prefabTable.TryAddSource(prefab, out var _))
				{
					InternalLogStreams.LogError?.Log($"Failed to add prefab asset {prefab.AssetGuid}, there is already a prefab entry with same guid");
				}
			}
			prefabTable.Options = PrefabOptions;
			SerializableSimulationBehaviourMeta[] behaviourMeta = BehaviourMeta;
			for (int i = 0; i < behaviourMeta.Length; i++)
			{
				SerializableSimulationBehaviourMeta serializableSimulationBehaviourMeta = behaviourMeta[i];
				Type type = serializableSimulationBehaviourMeta.Type;
				if (type == null)
				{
					InternalLogStreams.LogError?.Log($"Failed to resolve type: {serializableSimulationBehaviourMeta.Type}");
				}
				else
				{
					Config.ExecutionOrderOverrides.Add(type, serializableSimulationBehaviourMeta.ExecutionOrder);
				}
			}
		}

		protected override void OnDisable()
		{
			base.OnDisable();
			Config.PrefabTable?.Clear();
			Config.ExecutionOrderOverrides.Clear();
		}

		private static string GenerateDefaultContents()
		{
			return JsonUtility.ToJson(new NetworkProjectConfig(), prettyPrint: true);
		}
	}
	public enum NetworkSpawnStatus
	{
		Queued,
		Spawned,
		FailedToLoadPrefabSynchronously,
		FailedToCreateInstance,
		FailedClientCantSpawn,
		FailedLocalPlayerNotYetSet
	}
	[Flags]
	public enum NetworkSpawnFlags : short
	{
		DontDestroyOnLoad = 1,
		SharedModeStateAuthMasterClient = 2,
		SharedModeStateAuthLocalPlayer = 4
	}
	public readonly struct NetworkSpawnOp
	{
		internal class AsyncOpData
		{
			public NetworkSpawnStatus Status;

			public NetworkObject Object;

			public event Action Completed;

			public void Complete(in NetworkSpawnOp op)
			{
				Assert.Check(Status == NetworkSpawnStatus.Queued);
				Assert.Check(op.Status != NetworkSpawnStatus.Queued);
				Status = op.Status;
				Object = op.Object;
				this.Completed?.Invoke();
			}
		}

		public struct Awaiter(in NetworkSpawnOp op) : INotifyCompletion
		{
			private NetworkSpawnOp _op = op;

			public bool IsCompleted => _op.Status != NetworkSpawnStatus.Queued;

			public NetworkObject GetResult()
			{
				if (!IsCompleted)
				{
					SpinWait spinWait = default(SpinWait);
					while (!IsCompleted)
					{
						spinWait.SpinOnce();
					}
				}
				NetworkSpawnStatus status = _op.Status;
				Assert.Check(status != NetworkSpawnStatus.Queued);
				if (status != NetworkSpawnStatus.Spawned)
				{
					throw new NetworkObjectSpawnException(status);
				}
				return _op.Object;
			}

			public void OnCompleted(Action continuation)
			{
				if (IsCompleted)
				{
					continuation();
					return;
				}
				if (_op._data is AsyncOpData asyncOpData)
				{
					SynchronizationContext capturedContext = SynchronizationContext.Current;
					asyncOpData.Completed += delegate
					{
						if (capturedContext != null)
						{
							capturedContext.Post(delegate
							{
								continuation();
							}, null);
						}
						else
						{
							continuation();
						}
					};
					return;
				}
				throw new NotSupportedException();
			}
		}

		public readonly NetworkRunner Runner;

		internal readonly NetworkSpawnStatus _status;

		internal readonly object _data;

		public NetworkObject Object
		{
			[MethodImpl(MethodImplOptions.AggressiveInlining)]
			get
			{
				if (_status != NetworkSpawnStatus.Queued || !(_data is AsyncOpData { Object: var result }))
				{
					return (NetworkObject)_data;
				}
				return result;
			}
		}

		public NetworkSpawnStatus Status
		{
			[MethodImpl(MethodImplOptions.AggressiveInlining)]
			get
			{
				if (_status != NetworkSpawnStatus.Queued || !(_data is AsyncOpData { Status: var status }))
				{
					return _status;
				}
				return status;
			}
		}

		public bool IsSpawned => Status == NetworkSpawnStatus.Spawned;

		public bool IsQueued => Status == NetworkSpawnStatus.Queued;

		public bool IsFailed => Status != NetworkSpawnStatus.Spawned && Status != NetworkSpawnStatus.Queued;

		internal NetworkSpawnOp(NetworkRunner runner, NetworkSpawnStatus status, NetworkObject data)
		{
			Runner = runner;
			_status = status;
			_data = data;
		}

		internal NetworkSpawnOp(NetworkRunner runner, NetworkSpawnStatus status, AsyncOpData data)
		{
			Runner = runner;
			_status = status;
			_data = data;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		internal NetworkObject ConsumeSyncSpawn(NetworkObjectTypeId typeId)
		{
			if (_status == NetworkSpawnStatus.Queued || _status == NetworkSpawnStatus.Spawned)
			{
				return (NetworkObject)_data;
			}
			throw new NetworkObjectSpawnException(_status, typeId);
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		internal NetworkSpawnStatus ConsumeSyncSpawn(out NetworkObject obj)
		{
			obj = (NetworkObject)_data;
			return _status;
		}

		public Awaiter GetAwaiter()
		{
			return new Awaiter(this);
		}
	}
	public delegate void NetworkObjectSpawnDelegate(NetworkSpawnOp result);
	public sealed class NetworkObjectSpawnException : Exception
	{
		public NetworkObjectTypeId? TypeId { get; }

		public NetworkSpawnStatus Status { get; }

		public override string Message
		{
			get
			{
				string text = ((Status != NetworkSpawnStatus.FailedToLoadPrefabSynchronously) ? $"Failed to spawn: {Status}" : "Failed to load prefab synchronously. Use async spawn instead or enable EnqueueIncompleteSynchronousSpawns");
				if (TypeId.HasValue)
				{
					text += $" (prefab: {TypeId})";
				}
				return text;
			}
		}

		public NetworkObjectSpawnException(NetworkSpawnStatus status, NetworkObjectTypeId? id = null)
		{
			TypeId = id;
			Status = status;
		}
	}
