			{
				if (IsCompleted)
				{
					continuation();
					return;
				}
				SynchronizationContext capturedContext = SynchronizationContext.Current;
				_op.AddOnCompleted(delegate
				{
					if (capturedContext != null)
					{
						capturedContext.Post(delegate
						{
							continuation();
						}, null);
					}
					else
					{
						continuation();
					}
				});
			}
		}

