					for (int i = 1; i < 20; i++)
					{
						if (rc.Buffer->ReadBoolean())
						{
							_changedWords.Add(i);
							rc.Buffer->ReadInt64VarLength(6);
						}
					}
					word = 19;
				}
				SkipObjectData(rc, array, word, clearChangedWords: false);
			}

			private void ForceResendChangedWords(RecvContext rc, NetworkId id)
			{
