					meta.PlayerData = meta.SnapshotLatest.Header.PlayerData;
					if (flag5.HasValue)
					{
						_simulation._callbacks.ObjectStateAuthorityChanged(meta.Id, flag5.Value);
					}
					if (flag4.HasValue)
