	[Serializable]
	public class NetworkSimulationConfiguration
	{
		[InlineHelp]
		public bool Enabled;

		[InlineHelp]
		[DrawIf("Enabled", Hide = true)]
		public NetConfigSimulationOscillator.WaveShape DelayShape = NetConfigSimulationOscillator.WaveShape.Noise;

		[InlineHelp]
		[DrawIf("Enabled", Hide = true)]
		[Unit(Units.Seconds)]
		[RangeEx(0.0, 0.5)]
		public double DelayMin = 0.15;

		[InlineHelp]
		[DrawIf("Enabled", Hide = true)]
		[Unit(Units.Seconds)]
		[RangeEx(0.0, 0.5)]
		public double DelayMax = 0.15;

		[InlineHelp]
		[DrawIf("Enabled", Hide = true)]
		[Unit(Units.Seconds)]
		[RangeEx(0.0, 10.0)]
		public double DelayPeriod = 0.0;

		[InlineHelp]
		[DrawIf("Enabled", Hide = true)]
		[Unit(Units.Seconds)]
		[RangeEx(0.0, 1.0)]
		public double DelayThreshold = 0.0;

		[InlineHelp]
		[DrawIf("Enabled", Hide = true)]
		[Unit(Units.Seconds)]
		[RangeEx(0.0, 1.0)]
		public double AdditionalJitter = 0.05;

		[InlineHelp]
		[DrawIf("Enabled", Hide = true)]
		[Space]
		public NetConfigSimulationOscillator.WaveShape LossChanceShape = NetConfigSimulationOscillator.WaveShape.Noise;

		[InlineHelp]
		[DrawIf("Enabled", Hide = true)]
		[Unit(Units.NormalizedPercentage)]
		[RangeEx(0.0, 1.0)]
		public double LossChanceMin = 0.05;

		[InlineHelp]
		[DrawIf("Enabled", Hide = true)]
		[Unit(Units.NormalizedPercentage)]
		[RangeEx(0.0, 1.0)]
		public double LossChanceMax = 0.05;

		[InlineHelp]
		[DrawIf("Enabled", Hide = true)]
		[Unit(Units.NormalizedPercentage)]
		[RangeEx(0.0, 1.0)]
		public double LossChanceThreshold = 0.0;

		[InlineHelp]
		[DrawIf("Enabled", Hide = true)]
		[Unit(Units.Seconds)]
		[RangeEx(0.0, 10.0)]
		public double LossChancePeriod = 0.0;

		[InlineHelp]
		[DrawIf("Enabled", Hide = true)]
		[Unit(Units.NormalizedPercentage)]
		[RangeEx(0.0, 1.0)]
		public double AdditionalLoss = 0.0;

		public NetworkSimulationConfiguration Clone()
		{
			return (NetworkSimulationConfiguration)MemberwiseClone();
		}

		public NetConfigSimulation Create()
		{
			NetConfigSimulation defaults = NetConfigSimulation.Defaults;
			if (Enabled)
			{
				if (DelayMin == 0.0 && DelayMax == 0.0)
				{
					defaults.DelayOscillator.Min = 0.0;
					defaults.DelayOscillator.Max = 0.0;
				}
				else if (DelayMin > DelayMax)
				{
					defaults.DelayOscillator.Min = Math.Max(9.999999747378752E-05, DelayMax * 0.5);
					defaults.DelayOscillator.Max = Math.Max(9.999999747378752E-05, DelayMin * 0.5);
				}
				else
				{
					defaults.DelayOscillator.Min = Math.Max(9.999999747378752E-05, DelayMin * 0.5);
					defaults.DelayOscillator.Max = Math.Max(9.999999747378752E-05, DelayMax * 0.5);
				}
				defaults.DelayOscillator.Period = DelayPeriod;
				defaults.DelayOscillator.Shape = DelayShape;
				defaults.DelayOscillator.Threshold = DelayThreshold;
				defaults.DelayOscillator.Additional = AdditionalJitter * 0.5;
				if (LossChanceMin == 0.0 && LossChanceMax == 0.0)
				{
					defaults.LossOscillator.Min = 0.0;
					defaults.LossOscillator.Max = 0.0;
				}
				else if (LossChanceMin > LossChanceMax)
				{
					defaults.LossOscillator.Min = Math.Max(9.999999747378752E-05, LossChanceMax * 0.5);
					defaults.LossOscillator.Max = Math.Max(9.999999747378752E-05, LossChanceMin * 0.5);
				}
				else
				{
					defaults.LossOscillator.Min = Math.Max(9.999999747378752E-05, LossChanceMin * 0.5);
					defaults.LossOscillator.Max = Math.Max(9.999999747378752E-05, LossChanceMax * 0.5);
				}
				defaults.LossOscillator.Period = LossChancePeriod;
				defaults.LossOscillator.Shape = LossChanceShape;
				defaults.LossOscillator.Threshold = LossChanceThreshold;
				defaults.LossOscillator.Additional = AdditionalLoss;
			}
			return defaults;
		}
	}
	public class TimeSyncConfiguration
	{
		[InlineHelp]
		[Unit(Units.Seconds)]
		[RangeEx(1.0, 10.0)]
		public double SampleWindowSeconds = 1.0;

		[InlineHelp]
		[Unit(Units.Percentage)]
		[RangeEx(0.10000000149011612, 10.0)]
		public double MaxLateInputs = 1.0;

		[InlineHelp]
		[Unit(Units.Percentage)]
		[RangeEx(0.10000000149011612, 10.0)]
		public double MaxLateSnapshots = 5.0;

		[InlineHelp]
		[Unit(Units.Packets)]
		[RangeEx(0.0, 8.0)]
		public int RedundantInputs = 1;

		[InlineHelp]
		[Unit(Units.Packets)]
		[RangeEx(0.0, 8.0)]
		public int RedundantSnapshots = 1;

		internal double SampleWindowSecondsNormalized => Maths.Clamp(SampleWindowSeconds, 1.0, 10.0);

		internal double MaxLateInputsNormalized => Maths.Clamp(MaxLateInputs, 0.1, 10.0) / 100.0;

		internal double MaxLateSnapshotsNormalized => Maths.Clamp(MaxLateSnapshots, 0.1, 10.0) / 100.0;

		internal int RedundantInputsNormalized => Maths.Clamp(RedundantInputs, 0, 8);

		internal int RedundantSnapshotsNormalized => Maths.Clamp(RedundantSnapshots, 0, 8);

		private double MaxSimSpeedAdjust => 5.0;

		internal double MaxSimSpeedAdjustNormalized => Maths.Clamp(MaxSimSpeedAdjust, 1.0, 10.0) / 100.0;

		private double MaxInterpSpeedAdjust => 5.0;

		internal double MaxInterpSpeedAdjustNormalized => Maths.Clamp(MaxInterpSpeedAdjust, 1.0, 10.0) / 100.0;

		internal static TimeSyncConfiguration GetFromTickrate(TickRate.Resolved tickrate)
		{
			TimeSyncConfiguration timeSyncConfiguration = new TimeSyncConfiguration();
			switch (tickrate.ClientSend)
			{
			case 50:
			case 60:
			case 64:
			case 100:
			case 120:
			case 128:
			case 240:
			case 256:
				timeSyncConfiguration.MaxLateInputs = 1.0;
				timeSyncConfiguration.RedundantInputs = 1;
				break;
			case 30:
			case 32:
				timeSyncConfiguration.MaxLateInputs = 1.0;
				timeSyncConfiguration.RedundantInputs = 1;
				break;
			case 20:
			case 24:
				timeSyncConfiguration.MaxLateInputs = 1.0;
				timeSyncConfiguration.RedundantInputs = 1;
				break;
			case 8:
			case 10:
			case 16:
				timeSyncConfiguration.MaxLateInputs = 1.0;
				timeSyncConfiguration.RedundantInputs = 1;
				break;
			}
			switch (tickrate.ServerSend)
			{
			case 50:
			case 60:
			case 64:
			case 100:
			case 120:
			case 128:
			case 240:
			case 256:
				timeSyncConfiguration.MaxLateSnapshots = 5.0;
				timeSyncConfiguration.RedundantSnapshots = 1;
				break;
			case 30:
			case 32:
				timeSyncConfiguration.MaxLateSnapshots = 5.0;
				timeSyncConfiguration.RedundantSnapshots = 1;
				break;
			case 20:
			case 24:
				timeSyncConfiguration.MaxLateSnapshots = 5.0;
				timeSyncConfiguration.RedundantSnapshots = 1;
				break;
			case 8:
			case 10:
			case 16:
				timeSyncConfiguration.MaxLateSnapshots = 5.0;
				timeSyncConfiguration.RedundantSnapshots = 1;
				break;
			}
			return timeSyncConfiguration;
		}
	}
	internal class SimulationConnection
	{
		public const int INTEGRATOR_HISTORY_MULT = 10;

		private Simulation _simulation;

		private Dictionary<NetworkId, NetworkObjectConnectionData> _objects;

		private Queue<NetworkId> _objectsDestroyed;

		public PlayerRef Player;

		public bool AreaOfInterestHasBeenUpdated = false;

		public HashSet<int> AreaOfInterestCells = new HashSet<int>();

		public ulong MessagesInSequence;

		public ulong MessagesOutSequence;

		public SimulationMessageList MessagesIn;

		public SimulationMessageList MessagesOut;

		internal double LastSend;

		internal int ActiveStructsVersion = 0;

		internal int ActiveStructsIndex = 0;

		internal List<NetworkObjectConnectionData> ActiveStructs = new List<NetworkObjectConnectionData>();

		internal TimeSeries _packetRecvDelta;

		internal Timer _packetRecvDeltaTimer;

		internal SimulationInput.Buffer _inputs;

		internal TimeSeries _clientOffset;

		internal Tick _latestTickReceived;

		internal Tick _latestTickAcknowledged;

		internal NetworkObjectPriorityList ObjectPriorityList;

		internal unsafe NetConnection* Connection;

		internal NetConnectionId ConnectionId;

		internal HashSet<NetworkId> PendingDeleteMainTRSP = new HashSet<NetworkId>(NetworkId.Comparer);

		public unsafe int ConnectionIndex => Connection->LocalId.GroupIndex;

		public int DestroysPending => _objectsDestroyed.Count;

		public static implicit operator PlayerRef(SimulationConnection c)
		{
			Assert.Check(c.Player.IsRealPlayer);
			return c.Player;
		}

		internal SimulationConnection(Simulation simulation)
		{
			_simulation = simulation;
			int clientSend = TickRate.Resolve(simulation.Config.TickRateSelection).ClientSend;
			clientSend = Math.Max(clientSend, 5);
			_inputs = new SimulationInput.Buffer(simulation.ProjectConfig);
			_clientOffset = new TimeSeries(clientSend);
			_latestTickReceived = default(Tick);
			_packetRecvDelta = new TimeSeries(clientSend);
			_packetRecvDeltaTimer = default(Timer);
			_objects = new Dictionary<NetworkId, NetworkObjectConnectionData>(NetworkId.Comparer);
			_objectsDestroyed = new Queue<NetworkId>();
			ObjectPriorityList = new NetworkObjectPriorityList();
			ObjectPriorityList.Player = Player;
		}

		public int GetPriority(NetworkObjectMeta meta)
		{
			return meta.GetPriority(Player);
		}

		public bool TryGetObjectData(NetworkId id, out NetworkObjectConnectionData data)
		{
			return (data = GetObjectData(id, create: false)) != null;
		}

		public NetworkObjectConnectionData GetObjectData(NetworkId id, bool create, bool allowFail = false)
		{
			if (!_objects.TryGetValue(id, out var value) && create)
			{
				if (!_simulation.TryGetMeta(id, out var meta))
				{
					if (allowFail)
					{
						return null;
					}
					throw new InvalidOperationException($"tried to get connection object data for {id} but it does not exist");
				}
				value = new NetworkObjectConnectionData();
				value.Id = id;
				value.Filter = ulong.MaxValue;
				value.MainTRSP = meta.HasMainTRSP;
				if ((bool)meta.Instance && meta.Instance.NetworkedBehaviours != null)
				{
					NetworkBehaviour[] networkedBehaviours = meta.Instance.NetworkedBehaviours;
					for (int i = 0; i < networkedBehaviours.Length; i++)
					{
						if (!networkedBehaviours[i].DefaultReplicated)
						{
							value.Filter &= (ulong)(~(1L << networkedBehaviours[i].ObjectIndex));
						}
					}
				}
				_objects.Add(id, value);
				if (!meta.IsStruct && _simulation.Config.SchedulingEnabled)
				{
					ObjectPriorityList.SetActive(value, meta);
					if (_simulation.IsClient || !_simulation.Config.AreaOfInterestEnabled)
					{
						value.SetPlayerDataFlag(NetworkObjectHeaderPlayerDataFlags.InAreaOfInterest, _simulation);
					}
					if ((meta.Flags & NetworkObjectHeaderFlags.GlobalObjectInterest) == NetworkObjectHeaderFlags.GlobalObjectInterest)
					{
						value.SetPlayerDataFlag(NetworkObjectHeaderPlayerDataFlags.ForceInterest, _simulation);
						try
						{
							_simulation.Callbacks.ObjectEnterAOI(Player, id);
						}
						catch (Exception error)
						{
							InternalLogStreams.LogException?.Log(error);
						}
					}
				}
			}
			return value;
		}

		public bool DestroyedNextId(out NetworkId id)
		{
			if (_objectsDestroyed.Count > 0)
			{
				id = _objectsDestroyed.Dequeue();
				if (_objects.TryGetValue(id, out var value))
				{
					Assert.Check(value.Status == NetworkObjectConnectionDataStatus.DestroyUnconfirmed);
					value.Status = NetworkObjectConnectionDataStatus.DestroyPending;
				}
				return true;
			}
			id = default(NetworkId);
			return false;
		}

		public void ObjectData_Remove(NetworkId id)
		{
			if (_objects.TryGetValue(id, out var _))
			{
				_objects.Remove(id);
				PendingDeleteMainTRSP.Remove(id);
			}
		}

		public void ObjectData_Destroyed(NetworkId id, bool force = false)
		{
			if (_objects.TryGetValue(id, out var value))
			{
				if (value.Status != NetworkObjectConnectionDataStatus.DestroyUnconfirmed)
				{
					value.Status = NetworkObjectConnectionDataStatus.DestroyUnconfirmed;
					_objectsDestroyed.Enqueue(id);
					if (value.MainTRSP)
					{
						PendingDeleteMainTRSP.Add(id);
					}
				}
			}
			else if (force)
			{
				_objectsDestroyed.Enqueue(id);
			}
		}

		public bool? ObjectData_IsCreateUnconfirmed(NetworkId id)
		{
			NetworkObjectConnectionData objectData = GetObjectData(id, create: false);
			if (objectData == null)
			{
				return null;
			}
			return objectData.Status == NetworkObjectConnectionDataStatus.CreatedUnconfirmed;
		}

		public bool? ObjectData_IsDestroyUnconfirmed(NetworkId id)
		{
			NetworkObjectConnectionData objectData = GetObjectData(id, create: false);
			if (objectData == null)
			{
				return null;
			}
			return objectData.Status == NetworkObjectConnectionDataStatus.DestroyUnconfirmed;
		}

		public void Free(Simulation simulation)
		{
			simulation.FreeMessages(ref MessagesIn);
			simulation.FreeMessages(ref MessagesOut);
			LastSend = 0.0;
		}

		public void PacketReceiveDelta()
		{
			if (!_packetRecvDeltaTimer.IsRunning)
			{
				_packetRecvDeltaTimer = Timer.StartNew();
				Assert.Check(_packetRecvDelta.IsEmpty);
				if (_simulation.HasRuntimeConfig)
				{
					double value = ((!_simulation.IsClient) ? _simulation.RuntimeConfig.TickRate.ClientSendDelta : _simulation.RuntimeConfig.TickRate.ServerSendDelta);
					_packetRecvDelta.Add(value);
				}
			}
			else
			{
				double value = _packetRecvDeltaTimer.ElapsedInSeconds;
				if (!(value < 0.001))
				{
					_packetRecvDelta.Add(value);
					_packetRecvDeltaTimer.Restart();
				}
			}
		}

		public void ResetTimeFeedback()
		{
			_clientOffset.Clear();
			_packetRecvDelta.Clear();
			_packetRecvDeltaTimer.Reset();
		}

		public void InputReceiveDelta(Tick tick, double receive, double expected)
		{
			if (!(tick <= _latestTickReceived))
			{
				_latestTickReceived = tick;
				_clientOffset.Add(expected - receive);
			}
		}

		public void SetActive(NetworkObjectConnectionData data, NetworkObjectMeta meta)
		{
			ObjectPriorityList.SetActive(data, meta);
		}

		public void SetIdle(NetworkObjectConnectionData data)
		{
			ObjectPriorityList.SetIdle(data);
		}

		public void AddAlwaysInterested(NetworkObjectMeta meta)
		{
			if (meta == null || ((bool)meta.Instance && meta.Instance.ObjectInterest == NetworkObject.ObjectInterestModes.Global))
			{
				return;
			}
			Assert.Check((_simulation.Config.ReplicationFeatures & NetworkProjectConfig.ReplicationFeatures.SchedulingAndInterestManagement) == NetworkProjectConfig.ReplicationFeatures.SchedulingAndInterestManagement);
			NetworkObjectConnectionData objectData = GetObjectData(meta.Id, create: true);
			if ((objectData.UniqueData.Flags & NetworkObjectHeaderPlayerDataFlags.ForceInterest) != NetworkObjectHeaderPlayerDataFlags.ForceInterest)
			{
				if ((objectData.UniqueData.Flags & NetworkObjectHeaderPlayerDataFlags.AllInterestFlags) == 0)
				{
					_simulation.Callbacks.ObjectEnterAOI(Player, meta.Id);
				}
				SetActive(objectData, meta);
				objectData.SetPlayerDataFlag(NetworkObjectHeaderPlayerDataFlags.ForceInterest, _simulation);
			}
		}

		public void RemoveAlwaysInterested(NetworkObjectMeta meta)
		{
			if (meta == null)
			{
				return;
			}
			NetworkObject instance = meta.Instance;
			if ((object)instance != null && instance.ObjectInterest == NetworkObject.ObjectInterestModes.Global)
			{
				return;
			}
			Assert.Check((_simulation.Config.ReplicationFeatures & NetworkProjectConfig.ReplicationFeatures.SchedulingAndInterestManagement) == NetworkProjectConfig.ReplicationFeatures.SchedulingAndInterestManagement);
			NetworkObjectConnectionData objectData = GetObjectData(meta.Id, create: false);
			if (objectData != null && objectData.UniqueData.Flags.HasFlag(NetworkObjectHeaderPlayerDataFlags.ForceInterest))
			{
				if ((objectData.UniqueData.Flags & NetworkObjectHeaderPlayerDataFlags.AllInterestFlags) == NetworkObjectHeaderPlayerDataFlags.ForceInterest)
				{
					_simulation.Callbacks.ObjectExitAOI(Player, meta.Id);
				}
				objectData.ClearPlayerDataFlag(NetworkObjectHeaderPlayerDataFlags.ForceInterest, _simulation);
			}
		}
	}
	public class SimulationInput
	{
		public class Buffer
		{
			private NetworkProjectConfig _cfg;

			private TickRate.Resolved _rate;

			private Dictionary<Tick, SimulationInput> _map;

			private Dictionary<Tick, double> _time;

			private SimulationInputHeader _lastUsedInputHeaderData;

			public int Count => _map.Count;

			public bool Full => _map.Count == _rate.Client;

			public Buffer(NetworkProjectConfig cfg)
			{
				_cfg = cfg;
				_rate = TickRate.Resolve(_cfg.Simulation.TickRateSelection);
				_map = new Dictionary<Tick, SimulationInput>(new Tick.EqualityComparer());
				_time = new Dictionary<Tick, double>();
			}

			public void Clear()
			{
				_map.Clear();
				_time.Clear();
			}

			public int CopySortedTo(SimulationInput[] array)
			{
				Assert.Always(array.Length >= Count, "Array too small");
				Array.Clear(array, 0, array.Length);
				_map.Values.CopyTo(array, 0);
				ArraySpecialized.Sort(array, 0, _map.Count);
				for (int i = 0; i < _map.Count; i++)
				{
					Assert.Check(array[i]);
				}
				return _map.Count;
			}

			public bool Contains(Tick tick)
			{
				return _map.ContainsKey(tick);
			}

			public unsafe bool Remove(Tick tick, out SimulationInput removed)
			{
				_time.Remove(tick);
				if (_map.TryGetValue(tick, out removed))
				{
					_lastUsedInputHeaderData.Tick = removed.Header->Tick;
					_lastUsedInputHeaderData.InterpFrom = removed.Header->InterpFrom;
					_lastUsedInputHeaderData.InterpTo = removed.Header->InterpTo;
					_lastUsedInputHeaderData.InterpAlpha = removed.Header->InterpAlpha;
				}
				return _map.Remove(tick);
			}

			public double? GetInsertTime(Tick tick)
			{
				if (_time.TryGetValue(tick, out var value))
				{
					return value;
				}
				return null;
			}

			public SimulationInput Get(Tick tick)
			{
				if (_map.TryGetValue(tick, out var value))
				{
					Assert.Check(value);
					return value;
				}
				return null;
			}

			public SimulationInputHeader GetLastUsedInputHeader()
			{
				return _lastUsedInputHeaderData;
			}

			public unsafe bool Add(SimulationInput input, double? insertTime = null)
			{
				Assert.Check(input);
				Assert.Always(_map.Count < TickRate.Resolve(_cfg.Simulation.TickRateSelection).Client, "_map.Count < _cfg.Simulation.TickRate");
				if (Contains(input.Header->Tick))
				{
					return false;
				}
				_map.Add(input.Header->Tick, input);
				if (insertTime.HasValue)
				{
					_time.Add(input.Header->Tick, insertTime.Value);
				}
				return true;
			}
		}

		internal class Pool
		{
			private Allocator _allocator;

			private Stack<SimulationInput> _pool;

			private List<SimulationInput> _created;

			private SimulationConfig _config;

			private bool _disposed;

			public Pool(SimulationConfig config, Allocator allocator)
			{
				_pool = new Stack<SimulationInput>();
				_created = new List<SimulationInput>();
				_config = config;
				_allocator = allocator;
				_disposed = false;
			}

			public unsafe SimulationInput Acquire()
			{
				Assert.Check(!_disposed);
				SimulationInput simulationInput;
				if (_pool.Count > 0)
				{
					simulationInput = _pool.Pop();
					Assert.Check(simulationInput._pooled);
					simulationInput._pooled = false;
				}
				else
				{
					simulationInput = new SimulationInput();
					simulationInput._ptr = Allocator.AllocAndClearArray<int>(_allocator, _config.InputTotalWordCount);
					_created.Add(simulationInput);
				}
				Assert.Check(simulationInput._sent == 0);
				Assert.Check(!simulationInput._pooled);
				Assert.Check(simulationInput._player == PlayerRef.None);
				return simulationInput;
			}

			public unsafe void Release(SimulationInput input)
			{
				Assert.Check(!_disposed);
				Assert.Check(!input._pooled);
				Native.MemClear(input.Header, _config.InputTotalWordCount * 4);
				input._sent = 0;
				input._pooled = true;
				input._player = default(PlayerRef);
				_pool.Push(input);
			}

			public void Dispose()
			{
				_disposed = true;
				for (int i = 0; i < _created.Count; i++)
				{
					_created[i].Dispose(_allocator);
				}
				_created = null;
				_pool = null;
			}
		}

		private int _sent;

		private bool _pooled;

		private PlayerRef _player;

		internal unsafe int* _ptr;

		internal SimulationInput Prev;

		internal SimulationInput Next;

		public PlayerRef Player
		{
			get
			{
				Assert.Check(!_pooled);
				return _player;
			}
			set
			{
				Assert.Check(!_pooled);
				_player = value;
			}
		}

		public unsafe SimulationInputHeader* Header
		{
			get
			{
				Assert.Check(!_pooled);
				return (SimulationInputHeader*)_ptr;
			}
		}

		public unsafe int* Data
		{
			get
			{
				Assert.Check(!_pooled);
				return _ptr + 4;
			}
		}

		public int Sent
		{
			get
			{
				Assert.Check(!_pooled);
				return _sent;
			}
			set
			{
				Assert.Check(!_pooled);
				_sent = value;
			}
		}

		public unsafe void Clear(int wordCount)
		{
			Assert.Check(!_pooled);
			Native.MemClear(_ptr, wordCount * 4);
		}

		public unsafe void CopyFrom(SimulationInput source, int wordCount)
		{
			Assert.Check(!_pooled);
			Native.MemCpy(_ptr, source._ptr, wordCount * 4);
		}

		internal unsafe void Serialize(SimulationInput previous, SimulationConfig config, NetBitBufferSerializer serializer)
		{
			Assert.Check(!_pooled);
			int* ptr = _ptr;
			int* ptr2 = previous._ptr;
			if (config.Topology == Topologies.Shared)
			{
				if (serializer.Writing)
				{
					serializer.Buffer->WriteInt32VarLength(Header->Tick, 8);
				}
				else
				{
					Header->Tick = serializer.Buffer->ReadInt32VarLength(8);
				}
			}
			else if (serializer.Writing)
			{
				for (int i = 0; i < config.InputTotalWordCount; i++)
				{
					if (ptr[i] != ptr2[i])
					{
						serializer.Buffer->WriteBoolean(value: true);
						serializer.Buffer->WriteInt32VarLength(i, 8);
						serializer.Buffer->WriteInt64VarLength(Maths.ZigZagEncode((long)ptr[i] - (long)ptr2[i]), 8);
					}
				}
				serializer.Buffer->WriteBoolean(value: false);
			}
			else
			{
				Native.MemCpy(ptr, ptr2, config.InputTotalWordCount * 4);
				while (serializer.Buffer->ReadBoolean())
				{
					ptr[serializer.Buffer->ReadInt32VarLength(8)] += (int)Maths.ZigZagDecode(serializer.Buffer->ReadInt64VarLength(8));
				}
			}
		}

		internal unsafe void Dispose(Allocator allocator)
		{
			Allocator.Free(allocator, ref _ptr);
		}
	}
	internal class SimulationInputCollection
	{
		private int _count;

		private SimulationInput[] _byIndex;

		private Dictionary<PlayerRef, SimulationInput> _byPlayer;

		public int Count => _count;

		public SimulationInputCollection(int playerCount)
		{
			_byIndex = new SimulationInput[playerCount];
			_byPlayer = new Dictionary<PlayerRef, SimulationInput>(PlayerRef.Comparer);
		}

		public SimulationInput GetByIndex(int index)
		{
			if (index >= 0 && index < _count)
			{
				return _byIndex[index];
			}
			return null;
		}

		public SimulationInput GetByPlayer(PlayerRef player)
		{
			if (_byPlayer.TryGetValue(player, out var value))
			{
				return value;
			}
			return null;
		}

		public void Clear()
		{
			_count = 0;
			Array.Clear(_byIndex, 0, _byIndex.Length);
			_byPlayer.Clear();
		}

		public void AddInput(SimulationInput input)
		{
			int num = _count++;
			Assert.Check(_byIndex[num] == null);
			Assert.Check(!_byPlayer.ContainsKey(input.Player));
			_byIndex[num] = input;
			_byPlayer.Add(input.Player, input);
		}
	}
