	internal class VariableFeedback : IFeedbackController
	{
		private readonly double _Kp;

		private readonly double _Ki;

		private readonly double _Kd;

		private readonly double _outputMin;

		private readonly double _outputMax;

		private double _lastSample;

		private double _sum;

		private double _output;

		public VariableFeedback(double Kp, double Ki, double Kd, double outputMin, double outputMax)
		{
			Assert.Check(!double.IsNaN(Kp));
			Assert.Check(!double.IsInfinity(Kp));
			Assert.Check(!double.IsNaN(Ki));
			Assert.Check(!double.IsInfinity(Ki));
			Assert.Check(!double.IsNaN(Kd));
			Assert.Check(!double.IsInfinity(Kd));
			Assert.Check(!double.IsNaN(outputMin));
			Assert.Check(!double.IsNaN(outputMax));
			Assert.Check(outputMin <= outputMax);
			_Kp = Kp;
			_Ki = _Kp * Ki;
			_Kd = _Kp * Kd;
			_outputMin = outputMin;
			_outputMax = outputMax;
			_lastSample = 0.0;
			_sum = 0.0;
			_output = 0.0;
		}

		double IFeedbackController.Output()
		{
			return _output;
		}

		void IFeedbackController.Update(double sample, double target, double dt)
		{
			Assert.Check(!double.IsNaN(sample));
			Assert.Check(!double.IsInfinity(sample));
			Assert.Check(!double.IsNaN(target));
			Assert.Check(!double.IsInfinity(target));
			Assert.Check(!double.IsNaN(dt));
			Assert.Check(!double.IsInfinity(dt));
			Assert.Check(dt >= double.Epsilon);
			double num = target - sample;
			double num2 = sample - _lastSample;
			_output = _Kp * num;
			if (_output > _outputMax)
			{
				_output = _outputMax;
			}
			else if (_output < _outputMin)
			{
				_output = _outputMin;
			}
			_sum += _Ki * dt * num - _Kd / dt * num2;
			_output += _sum;
			if (_output > _outputMax)
			{
				_sum -= _output - _outputMax;
				_output = _outputMax;
			}
			else if (_output < _outputMin)
			{
				_sum += _outputMin - _output;
				_output = _outputMin;
			}
		}

		void IFeedbackController.Reset()
		{
			_lastSample = 0.0;
			_sum = 0.0;
			_output = 0.0;
		}

		void IFeedbackController.ResetOutput()
		{
			_output = 0.0;
		}
	}
	public struct NetworkInput
	{
		private unsafe uint* _ptr;

		private int _wordCount;

		public int WordCount => _wordCount;

		public unsafe uint* Data => (_ptr == null) ? null : (_ptr + 1);

		public unsafe bool IsValid => _ptr != null;

		internal unsafe uint* Ptr => _ptr;

		internal unsafe int TypeKey
		{
			get
			{
				return (_ptr == null) ? (-1) : ((int)(*_ptr));
			}
			set
			{
				if (_ptr != null)
				{
					*_ptr = (uint)value;
				}
			}
		}

		public Type Type
		{
			get
			{
				int typeKey = TypeKey;
				if (typeKey == -1)
				{
					return null;
				}
				return NetworkInputUtils.GetType(typeKey);
			}
		}

		internal unsafe static NetworkInput FromRaw(uint* ptr, int wordCount)
		{
			return new NetworkInput
			{
				_ptr = ptr,
				_wordCount = wordCount
			};
		}

		internal unsafe static NetworkInput FromRaw(int* ptr, int wordCount)
		{
			return new NetworkInput
			{
				_ptr = (uint*)ptr,
				_wordCount = wordCount
			};
		}

		public unsafe bool TryGet<T>(out T input) where T : unmanaged, INetworkInput
		{
			Assert.Check(IsValid);
			if (_ptr == null || TypeKey != NetworkInputUtils.GetTypeKey(typeof(T)))
			{
				input = default(T);
				return false;
			}
			input = *(T*)Data;
			return true;
		}

		public unsafe bool TrySet<T>(T input) where T : unmanaged, INetworkInput
		{
			Assert.Check(IsValid);
			if (_ptr == null || TypeKey != NetworkInputUtils.GetTypeKey(typeof(T)))
			{
				return false;
			}
			*(T*)Data = input;
			return true;
		}

		public unsafe T Get<T>() where T : unmanaged, INetworkInput
		{
			Assert.Check(IsValid);
			Convert<T>();
			return *(T*)Data;
		}

		public unsafe bool Set<T>(T value) where T : unmanaged, INetworkInput
		{
			Assert.Check(IsValid);
			bool result = Convert<T>();
			*(T*)Data = value;
			return result;
		}

		internal unsafe bool Set(Type type, void* value)
		{
			Assert.Check(IsValid);
			int wordCount = NetworkInputUtils.GetWordCount(type);
			if (wordCount >= _wordCount)
			{
				throw new ArgumentException($"Expected max {_wordCount}, got: {wordCount}", "type");
			}
			bool flag = Convert(type);
			Native.MemCpy(Data, value, wordCount * 4);
			return true;
		}

		public bool Convert<T>() where T : unmanaged, INetworkInput
		{
			return Convert(typeof(T));
		}

		public unsafe bool Convert(Type type)
		{
			Assert.Check(IsValid);
			int typeKey = NetworkInputUtils.GetTypeKey(type);
			if (typeKey != TypeKey)
			{
				Native.MemClear(_ptr, _wordCount * 4);
				TypeKey = typeKey;
				return true;
			}
			return false;
		}

		public bool Is<T>() where T : unmanaged, INetworkInput
		{
			Assert.Check(IsValid);
			return TypeKey == NetworkInputUtils.GetTypeKey(typeof(T));
		}
	}
