namespace Fusion.Internal
{
	[Serializable]
	public abstract class UnityArraySurrogate<T, ReaderWriter> : UnitySurrogateBase where T : unmanaged where ReaderWriter : unmanaged, IElementReaderWriter<T>
	{
		public abstract T[] DataProperty { get; set; }

		public unsafe override void Read(int* data, int capacity)
		{
			ReaderWriter val = default(ReaderWriter);
			T[] array = DataProperty;
			Array.Resize(ref array, capacity);
			for (int i = 0; i < capacity; i++)
			{
				array[i] = val.Read((byte*)data, i);
			}
			DataProperty = array;
		}

		public unsafe override void Write(int* data, int capacity)
		{
			ReaderWriter val = default(ReaderWriter);
			T[] array = DataProperty;
			Array.Resize(ref array, capacity);
			for (int i = 0; i < capacity; i++)
			{
				val.Write((byte*)data, i, array[i]);
			}
		}

		public override void Init(int capacity)
		{
			DataProperty = new T[capacity];
		}
	}
	[Serializable]
	public abstract class UnityDictionarySurrogate<TKeyType, TKeyReaderWriter, TValueType, TValueReaderWriter> : UnitySurrogateBase where TKeyType : unmanaged where TKeyReaderWriter : unmanaged, IElementReaderWriter<TKeyType> where TValueType : unmanaged where TValueReaderWriter : unmanaged, IElementReaderWriter<TValueType>
	{
		private static IElementReaderWriter<TKeyType> _keyReaderWriter = new TKeyReaderWriter();

		private static IElementReaderWriter<TValueType> _valReaderWriter = new TValueReaderWriter();

		public abstract SerializableDictionary<TKeyType, TValueType> DataProperty { get; set; }

		public unsafe override void Read(int* data, int capacity)
		{
			bool flag = false;
			SerializableDictionary<TKeyType, TValueType> dataProperty = DataProperty;
			NetworkDictionary<TKeyType, TValueType> networkDictionary = new NetworkDictionary<TKeyType, TValueType>(data, capacity, _keyReaderWriter, _valReaderWriter);
			if (networkDictionary.Count != dataProperty.Count)
			{
				flag = true;
			}
			else
			{
				foreach (KeyValuePair<TKeyType, TValueType> item in networkDictionary)
				{
					if (!dataProperty.ContainsKey(item.Key))
					{
						flag = true;
						break;
					}
					dataProperty[item.Key] = item.Value;
				}
			}
			if (flag)
			{
				dataProperty.Clear();
				foreach (KeyValuePair<TKeyType, TValueType> item2 in networkDictionary)
				{
					dataProperty.Add(item2.Key, item2.Value);
				}
			}
			dataProperty.Store();
		}

		public unsafe override void Write(int* data, int capacity)
		{
			NetworkDictionary<TKeyType, TValueType> networkDictionary = new NetworkDictionary<TKeyType, TValueType>(data, capacity, _keyReaderWriter, _valReaderWriter);
			networkDictionary.Clear();
			foreach (KeyValuePair<TKeyType, TValueType> item in DataProperty)
			{
				networkDictionary.Add(item.Key, item.Value);
			}
		}

		public override void Init(int capacity)
		{
			DataProperty = new SerializableDictionary<TKeyType, TValueType>();
		}
	}
	[Serializable]
	public abstract class UnityLinkedListSurrogate<T, ReaderWriter> : UnitySurrogateBase where T : unmanaged where ReaderWriter : unmanaged, IElementReaderWriter<T>
	{
		private static IElementReaderWriter<T> _readerWriter = new ReaderWriter();

		public abstract T[] DataProperty { get; set; }

		public unsafe override void Read(int* data, int capacity)
		{
			NetworkLinkedList<T> networkLinkedList = new NetworkLinkedList<T>((byte*)data, capacity, _readerWriter);
			T[] array = DataProperty;
			Array.Resize(ref array, networkLinkedList.Count);
			int num = 0;
			foreach (T item in networkLinkedList)
			{
				array[num++] = item;
			}
			DataProperty = array;
		}

		public unsafe override void Write(int* data, int capacity)
		{
			NetworkLinkedList<T> networkLinkedList = new NetworkLinkedList<T>((byte*)data, capacity, _readerWriter);
			networkLinkedList.Clear();
			T[] dataProperty = DataProperty;
			foreach (T value in dataProperty)
			{
				networkLinkedList.Add(value);
			}
		}

		public override void Init(int capacity)
		{
			DataProperty = Array.Empty<T>();
		}
	}
	[Serializable]
	public abstract class UnitySurrogateBase : IUnitySurrogate
	{
		public unsafe abstract void Read(int* data, int capacity);

		public unsafe abstract void Write(int* data, int capacity);

		public abstract void Init(int capacity);
	}
	public interface IUnitySurrogate
	{
		unsafe void Read(int* data, int capacity);

		unsafe void Write(int* data, int capacity);
	}
	[Serializable]
	public abstract class UnityValueSurrogate<T, TReaderWriter> : UnitySurrogateBase, IUnityValueSurrogate<T>, IUnitySurrogate where TReaderWriter : unmanaged, IElementReaderWriter<T>
	{
		public abstract T DataProperty { get; set; }

		public unsafe override void Read(int* data, int capacity)
		{
			DataProperty = default(TReaderWriter).Read((byte*)data, 0);
		}

		public unsafe override void Write(int* data, int capacity)
		{
			default(TReaderWriter).Write((byte*)data, 0, DataProperty);
		}

		public override void Init(int capacity)
		{
		}
	}
	public interface IUnityValueSurrogate<T> : IUnitySurrogate
	{
		T DataProperty { get; set; }
	}
