	public class SnapshotHistoryDraw : IEnumerable<HitboxColliderContainerDraw>, IEnumerable
	{
		private HitboxBuffer _buffer;

		private HitboxColliderContainerDraw _containerDraw = new HitboxColliderContainerDraw();

		internal SnapshotHistoryDraw(HitboxBuffer buffer)
		{
			_buffer = buffer;
		}

		public IEnumerator<HitboxColliderContainerDraw> GetEnumerator()
		{
			for (int i = 0; i < _buffer.Length; i++)
			{
				_containerDraw._container = _buffer._buffer[i];
				yield return _containerDraw;
			}
			_containerDraw._container = null;
		}

		IEnumerator IEnumerable.GetEnumerator()
		{
			return GetEnumerator();
		}
	}
	public class HitboxColliderContainerDraw : IEnumerable<ColliderDrawInfo>, IEnumerable
	{
		internal HitboxBuffer.HitboxSnapshot _container;

		private ColliderDrawInfo _drawInfo = new ColliderDrawInfo();

		public IEnumerator<ColliderDrawInfo> GetEnumerator()
		{
			_drawInfo.SetContainer(_container);
			for (int i = 1; i <= _container.CollidersCount; i++)
			{
				if (_container.GetCollider(i).Active && _container.GetCollider(i).Used)
				{
					yield return _drawInfo.FromHitboxCollider(i);
				}
			}
		}

		IEnumerator IEnumerable.GetEnumerator()
		{
			return GetEnumerator();
		}
	}
	public class BVHDraw : IEnumerable<BVHNodeDrawInfo>, IEnumerable
	{
		internal HitboxBuffer _buffer;

		private BVHNodeDrawInfo _drawInfo;

		private Stack<BVHNode> _reusableStack = new Stack<BVHNode>();

		internal BVHDraw(HitboxBuffer buffer)
		{
			_buffer = buffer;
			_drawInfo = new BVHNodeDrawInfo(_buffer);
		}

		public IEnumerator<BVHNodeDrawInfo> GetEnumerator()
		{
			_reusableStack.Clear();
			_reusableStack.Push(_drawInfo.Buffer.BVH.rootBVH);
			while (_reusableStack.Count > 0)
			{
				BVHNode node = _reusableStack.Pop();
				if (node.IsValid)
				{
					yield return _drawInfo.FromBVHNode(ref node);
					if (node.HasLeft)
					{
						_reusableStack.Push(node.GetLeft(_drawInfo.Buffer.BVH));
					}
					if (node.HasRight)
					{
						_reusableStack.Push(node.GetRight(_drawInfo.Buffer.BVH));
					}
				}
			}
		}

		IEnumerator IEnumerable.GetEnumerator()
		{
			return GetEnumerator();
		}
	}
