	[Serializable]
	public class RaycastAllQuery : RaycastQuery
	{
		private RaycastHit[] _physXRaycastHits;

		private RaycastHit2D[] _box2DRaycastHits;

		public RaycastAllQuery(ref RaycastQueryParams raycastQueryParams)
			: base(ref raycastQueryParams)
		{
			_physXRaycastHits = new RaycastHit[raycastQueryParams.StaticHitsCapacity];
			_box2DRaycastHits = new RaycastHit2D[raycastQueryParams.StaticHitsCapacity];
		}

		public RaycastAllQuery(ref RaycastQueryParams raycastQueryParams, RaycastHit[] physXRaycastHitsCache, RaycastHit2D[] box2DRaycastHitCache)
			: base(ref raycastQueryParams)
		{
			_physXRaycastHits = physXRaycastHitsCache;
			_box2DRaycastHits = box2DRaycastHitCache;
		}

		internal override bool NarrowPhase(IHitboxColliderContainer container, HashSet<int> candidates, List<HitboxHit> hits)
		{
			int count = hits.Count;
			foreach (int candidate in candidates)
			{
				ref HitboxCollider collider = ref container.GetCollider(candidate);
				if (NarrowPhaseRay(ref collider, Origin, Direction, Length, out var point, out var normal, out var distance))
				{
					hits.Add(CreateHitboxHit(ref collider, point, distance, normal));
				}
			}
			return hits.Count > count;
		}

		internal override void PerformStaticQuery(NetworkRunner runner, List<LagCompensatedHit> hits, HitOptions options)
		{
			if ((options & HitOptions.IncludePhysX) != HitOptions.None)
			{
				int num = runner.GetPhysicsScene().Raycast(Origin, Direction, _physXRaycastHits, Length, LayerMask, TriggerInteraction);
				for (int i = 0; i < num; i++)
				{
					hits.Add((LagCompensatedHit)_physXRaycastHits[i]);
				}
			}
			else if ((options & HitOptions.IncludeBox2D) != HitOptions.None)
			{
				int num2 = runner.GetPhysicsScene2D().Raycast(Origin, Direction, Length, _box2DRaycastHits, LayerMask);
				for (int j = 0; j < num2; j++)
				{
					hits.Add((LagCompensatedHit)_box2DRaycastHits[j]);
				}
			}
		}
	}
	[Serializable]
	public class RaycastQuery : Query
	{
		public Vector3 Direction;

		public Vector3 Origin;

		public float Length;

		private RaycastHit _raycastHit;

		private RaycastHit2D _raycastHit2D;

		public RaycastQuery(ref RaycastQueryParams raycastQueryParams)
			: base(ref raycastQueryParams.QueryParams)
		{
			Direction = raycastQueryParams.Direction;
			Origin = raycastQueryParams.Origin;
			Length = raycastQueryParams.Length;
		}

		protected override bool Check(ref AABB bounds)
		{
			Vector3 min = bounds.Min;
			Vector3 max = bounds.Max;
			float num = Length * Length;
			bool flag = true;
			bool flag2 = false;
			bool flag3 = false;
			bool flag4 = false;
			Vector3 vector = default(Vector3);
			Vector3 vector2 = default(Vector3);
			Vector3 vector3 = default(Vector3);
			if (Origin.x < min.x)
			{
				vector2.x = min.x;
				flag = false;
			}
			else if (Origin.x > max.x)
			{
				vector2.x = max.x;
				flag = false;
			}
			else
			{
				flag2 = true;
			}
			if (Origin.y < min.y)
			{
				vector2.y = min.y;
				flag = false;
			}
			else if (Origin.y > max.y)
			{
				vector2.y = max.y;
				flag = false;
			}
			else
			{
				flag3 = true;
			}
			if (Origin.z < min.z)
			{
				vector2.z = min.z;
				flag = false;
			}
			else if (Origin.z > max.z)
			{
				vector2.z = max.z;
				flag = false;
			}
			else
			{
				flag4 = true;
			}
			if (flag)
			{
				vector3 = Origin;
				return true;
			}
			if (Direction.x != 0f && !flag2)
			{
				vector.x = (vector2.x - Origin.x) / Direction.x;
			}
			else
			{
				vector.x = -1f;
			}
			if (Direction.y != 0f && !flag3)
			{
				vector.y = (vector2.y - Origin.y) / Direction.y;
			}
			else
			{
				vector.y = -1f;
			}
			if (Direction.z != 0f && !flag4)
			{
				vector.z = (vector2.z - Origin.z) / Direction.z;
			}
			else
			{
				vector.z = -1f;
			}
			int num2 = 0;
			float num3 = vector.x;
			if (num3 < vector.y)
			{
				num2 = 1;
				num3 = vector.y;
			}
			if (num3 < vector.z)
			{
				num2 = 2;
				num3 = vector.z;
			}
			if (num3 < 0f)
			{
				return false;
			}
			if (num2 != 0)
			{
				vector3.x = Origin.x + num3 * Direction.x;
				if (vector3.x < min.x || vector3.x > max.x)
				{
					return false;
				}
			}
			else
			{
				vector3.x = vector2.x;
			}
			if (num2 != 1)
			{
				vector3.y = Origin.y + num3 * Direction.y;
				if (vector3.y < min.y || vector3.y > max.y)
				{
					return false;
				}
			}
			else
			{
				vector3.y = vector2.y;
			}
			if (num2 != 2)
			{
				vector3.z = Origin.z + num3 * Direction.z;
				if (vector3.z < min.z || vector3.z > max.z)
				{
					return false;
				}
			}
			else
			{
				vector3.z = vector2.z;
			}
			Vector3 origin = Origin;
			origin.x -= vector3.x;
			origin.y -= vector3.y;
			origin.z -= vector3.z;
			if (origin.sqrMagnitude <= num)
			{
				return true;
			}
			return false;
		}

		internal override bool NarrowPhase(IHitboxColliderContainer container, HashSet<int> candidates, List<HitboxHit> hits)
		{
			int count = hits.Count;
			float num = float.MaxValue;
			foreach (int candidate in candidates)
			{
				ref HitboxCollider collider = ref container.GetCollider(candidate);
				if (NarrowPhaseRay(ref collider, Origin, Direction, Length, out var point, out var normal, out var distance) && !(distance >= num))
				{
					num = distance;
					hits.Insert(hits.Count, CreateHitboxHit(ref collider, point, distance, normal));
				}
			}
			return hits.Count > count;
		}

		internal override void PerformStaticQuery(NetworkRunner runner, List<LagCompensatedHit> hits, HitOptions options)
		{
			if ((options & HitOptions.IncludePhysX) != HitOptions.None)
			{
				if (runner.GetPhysicsScene().Raycast(Origin, Direction, out _raycastHit, Length, LayerMask, TriggerInteraction))
				{
					hits.Add((LagCompensatedHit)_raycastHit);
				}
			}
			else if ((options & HitOptions.IncludeBox2D) != HitOptions.None)
			{
				_raycastHit2D = runner.GetPhysicsScene2D().Raycast(Origin, Direction, Length, LayerMask);
				if (_raycastHit2D.collider != null)
				{
					hits.Add((LagCompensatedHit)_raycastHit2D);
				}
			}
		}

		internal bool NarrowPhaseRay(ref HitboxCollider c, Vector3 origin, Vector3 direction, float length, out Vector3 point, out Vector3 normal, out float distance)
		{
			switch (c.Type)
			{
			case HitboxTypes.Box:
			{
				Matrix4x4 inverse2 = c.LocalToWorld.inverse;
				Vector3 origin2 = inverse2.MultiplyPoint(origin) - c.Offset;
				Vector3 dir = inverse2.MultiplyVector(direction);
				Vector3 minB = -c.BoxExtents;
				Vector3 maxB = c.BoxExtents;
				if (LagCompensationUtils.RayAABB(ref minB, ref maxB, ref origin2, ref dir, length * length, out point, out normal, out distance))
				{
					point = c.LocalToWorld.MultiplyPoint(point + c.Offset);
					normal = c.LocalToWorld.MultiplyVector(normal);
					return true;
				}
				break;
			}
			case HitboxTypes.Sphere:
			{
				Vector3 center = c.LocalToWorld.MultiplyPoint(c.Offset);
				if (LagCompensationUtils.RaySphereIntersection(origin, direction, length, center, c.Radius, out point, out normal, out distance))
				{
					return true;
				}
				break;
			}
			case HitboxTypes.Capsule:
			{
				Matrix4x4 inverse = c.LocalToWorld.inverse;
				Vector3 rayLocalOrigin = inverse.MultiplyPoint(origin);
				Vector3 vector = inverse.MultiplyVector(direction);
				if (LagCompensationUtils.LocalRayCapsuleIntersection(c.CapsuleLocalTopCenter, c.CapsuleLocalBottomCenter, c.Radius, rayLocalOrigin, vector.normalized, length, out point, out normal, out distance))
				{
					point = c.LocalToWorld.MultiplyPoint(point);
					normal = c.LocalToWorld.MultiplyVector(normal);
					return true;
				}
				break;
			}
			}
			point = default(Vector3);
			normal = default(Vector3);
			distance = 0f;
			return false;
		}
	}
	[Serializable]
	public struct RaycastQueryParams(QueryParams queryParams, Vector3 origin, Vector3 direction, float length, int staticHitsCapacity = 64)
	{
		public QueryParams QueryParams = queryParams;

		public Vector3 Origin = origin;

		public Vector3 Direction = direction;

		public float Length = length;

		public int StaticHitsCapacity = staticHitsCapacity;
	}
	[Serializable]
	public class SphereOverlapQuery : Query
	{
		public Vector3 Center;

		public float Radius;

		private Collider[] _physXOverlapHits;

		private Collider2D[] _box2DOverlapHits;

		public SphereOverlapQuery(ref SphereOverlapQueryParams sphereOverlapParams)
			: base(ref sphereOverlapParams.QueryParams)
		{
			Center = sphereOverlapParams.Center;
			Radius = sphereOverlapParams.Radius;
			_physXOverlapHits = new Collider[sphereOverlapParams.StaticHitsCapacity];
			_box2DOverlapHits = new Collider2D[sphereOverlapParams.StaticHitsCapacity];
		}

		public SphereOverlapQuery(ref SphereOverlapQueryParams sphereOverlapParams, Collider[] physXOverlapHitsCache, Collider2D[] box2DOverlapHitsCache)
			: base(ref sphereOverlapParams.QueryParams)
		{
			Center = sphereOverlapParams.Center;
			Radius = sphereOverlapParams.Radius;
			_physXOverlapHits = physXOverlapHitsCache;
			_box2DOverlapHits = box2DOverlapHitsCache;
		}

		protected override bool Check(ref AABB bounds)
		{
			return LagCompensationUtils.LocalAABBSphereIntersection(bounds.Extents, Center - bounds.Center, Radius);
		}

		internal override bool NarrowPhase(IHitboxColliderContainer container, HashSet<int> candidates, List<HitboxHit> hits)
		{
			bool result = false;
			foreach (int candidate in candidates)
			{
				ref HitboxCollider collider = ref container.GetCollider(candidate);
				if (NarrowPhaseSphere(ref collider, Center, Radius, out var point, out var normal))
				{
					result = true;
					hits.Add(CreateHitboxHit(ref collider, point, 0f, normal));
				}
			}
			return result;
		}

		internal override void PerformStaticQuery(NetworkRunner runner, List<LagCompensatedHit> hits, HitOptions options)
		{
			if ((options & HitOptions.IncludePhysX) != HitOptions.None)
			{
				int num = runner.GetPhysicsScene().OverlapSphere(Center, Radius, _physXOverlapHits, LayerMask, TriggerInteraction);
				for (int i = 0; i < num; i++)
				{
					Collider collider = _physXOverlapHits[i];
					LagCompensatedHit item = new LagCompensatedHit
					{
						Collider = collider,
						Normal = default(Vector3),
						Distance = 0f,
						GameObject = collider.gameObject,
						Type = HitType.PhysX
					};
					hits.Add(item);
				}
			}
			else if ((options & HitOptions.IncludeBox2D) != HitOptions.None)
			{
				int num2 = runner.GetPhysicsScene2D().OverlapCircle(Center, Radius, _box2DOverlapHits, LayerMask);
				for (int j = 0; j < num2; j++)
				{
					Collider2D collider2D = _box2DOverlapHits[j];
					LagCompensatedHit item2 = new LagCompensatedHit
					{
						Collider2D = collider2D,
						Normal = default(Vector3),
						Distance = 0f,
						GameObject = collider2D.gameObject,
						Type = HitType.Box2D
					};
					hits.Add(item2);
				}
			}
		}

		internal bool NarrowPhaseSphere(ref HitboxCollider c, Vector3 origin, float radius, out Vector3 point, out Vector3 normal)
		{
			switch (c.Type)
			{
			case HitboxTypes.Box:
			{
				Vector3 sphereCenter2 = c.LocalToWorld.inverse.MultiplyPoint(origin) - c.Offset;
				if (LagCompensationUtils.LocalAABBSphereContact(c.BoxExtents, sphereCenter2, radius, out var contact))
				{
					point = c.LocalToWorld.MultiplyPoint(contact.Point + c.Offset);
					normal = c.LocalToWorld.MultiplyVector(contact.Normal);
					return true;
				}
				break;
			}
			case HitboxTypes.Sphere:
			{
				Vector3 centerB = c.LocalToWorld.MultiplyPoint(c.Offset);
				if (LagCompensationUtils.SphereSphere(origin, radius, centerB, c.Radius, out point, out normal))
				{
					return true;
				}
				break;
			}
			case HitboxTypes.Capsule:
			{
				Vector3 sphereCenter = c.LocalToWorld.inverse.MultiplyPoint(origin);
				if (LagCompensationUtils.LocalSphereCapsuleIntersection(c.CapsuleLocalTopCenter, c.CapsuleLocalBottomCenter, c.Radius, sphereCenter, radius, out var contactData))
				{
					point = c.LocalToWorld.MultiplyPoint(contactData.Point);
					normal = c.LocalToWorld.MultiplyVector(contactData.Normal);
					return true;
				}
				break;
			}
			}
			point = default(Vector3);
			normal = default(Vector3);
			return false;
		}
	}
	[Serializable]
	public struct SphereOverlapQueryParams(QueryParams queryParams, Vector3 center, float radius, int staticHitsCapacity)
	{
		public QueryParams QueryParams = queryParams;

		public Vector3 Center = center;

		public float Radius = radius;

		public int StaticHitsCapacity = staticHitsCapacity;
	}
